"use client";

import * as React from "react";

import { cn } from "./lib/utils";

export type CellContentProps = {
  children: React.ReactNode;
  wrap?: boolean;
  truncate?: boolean;
  /** Native tooltip when truncated (full text). */
  title?: string;
  className?: string;
};

/**
 * Renders cell/header text with optional wrap or ellipsis truncate.
 * Truncate uses overflow hidden + text-ellipsis + nowrap (…).
 */
export function CellContent({
  children,
  wrap = false,
  truncate = true,
  title,
  className,
}: CellContentProps) {
  if (wrap) {
    return (
      <div className={cn("min-w-0 whitespace-normal break-words", className)}>
        {children}
      </div>
    );
  }

  if (truncate) {
    const textTitle =
      title ??
      (typeof children === "string" || typeof children === "number"
        ? String(children)
        : undefined);

    return (
      <div
        className={cn("min-w-0 max-w-full truncate", className)}
        title={textTitle}
      >
        {children}
      </div>
    );
  }

  return (
    <div className={cn("min-w-0 whitespace-nowrap", className)}>{children}</div>
  );
}

"use client";

import * as React from "react";
import {
  ArrowDownIcon,
  ArrowUpIcon,
  EyeOffIcon,
  MoreVerticalIcon,
  PinIcon,
  PinOffIcon,
} from "lucide-react";
import {
  FloatingPortal,
  autoUpdate,
  flip,
  offset,
  shift,
  useClick,
  useDismiss,
  useFloating,
  useInteractions,
  useRole,
} from "@floating-ui/react";

import { Button } from "./components/ui/button";
import { cn } from "./lib/utils";
import { useDataTableLocale } from "./locale-text";
import type { DataTableSort, SortDirection } from "./types";

export type ColumnHeaderMenuProps = {
  columnKey: string;
  header: string;
  sortable?: boolean;
  sortRule?: DataTableSort;
  pinned?: "left" | "right" | false;
  radiusClass?: string;
  popoverOffset?: number;
  onSort?: (direction: SortDirection | null) => void;
  onHide?: () => void;
  onPin?: (side: "left" | "right" | null) => void;
};

export function ColumnHeaderMenu({
  columnKey,
  header,
  sortable = false,
  sortRule,
  pinned = false,
  radiusClass = "rounded-xs",
  popoverOffset = 8,
  onSort,
  onHide,
  onPin,
}: ColumnHeaderMenuProps) {
  const locale = useDataTableLocale();
  const [open, setOpen] = React.useState(false);

  const { refs, floatingStyles, context } = useFloating({
    open,
    onOpenChange: setOpen,
    placement: "bottom-end",
    whileElementsMounted: autoUpdate,
    middleware: [
      offset(popoverOffset),
      flip({ padding: 8 }),
      shift({ padding: 8 }),
    ],
  });

  const click = useClick(context);
  const dismiss = useDismiss(context);
  const role = useRole(context, { role: "menu" });
  const { getReferenceProps, getFloatingProps } = useInteractions([
    click,
    dismiss,
    role,
  ]);

  const itemClass =
    "flex w-full items-center gap-2 px-2 py-1.5 text-left text-sm hover:bg-muted outline-none";

  const runAction = (action: () => void) => (event: React.PointerEvent) => {
    // PointerDown runs before dismiss unmounts the floating menu.
    event.preventDefault();
    event.stopPropagation();
    action();
    setOpen(false);
  };

  return (
    <>
      <Button
        type="button"
        variant="ghost"
        size="icon-xs"
        ref={refs.setReference}
        aria-label={locale.columnMenuAria(header)}
        aria-expanded={open}
        data-slot="data-table-column-menu-trigger"
        className={cn(
          "size-6 shrink-0 text-muted-foreground opacity-0 transition-opacity group-hover/th:opacity-100 focus-visible:opacity-100 data-[state=open]:opacity-100",
          open && "opacity-100",
          radiusClass,
        )}
        data-state={open ? "open" : "closed"}
        {...getReferenceProps({
          onClick: (event) => event.stopPropagation(),
        })}
      >
        <MoreVerticalIcon className="size-3.5" />
      </Button>

      {open ? (
        <FloatingPortal>
          <div
            ref={refs.setFloating}
            style={floatingStyles}
            data-slot="data-table-column-menu"
            data-column-key={columnKey}
            className={cn(
              "z-50 min-w-44 border border-input bg-popover p-1 text-popover-foreground shadow-md",
              radiusClass,
            )}
            {...getFloatingProps({
              onClick: (event) => event.stopPropagation(),
            })}
          >
            {sortable ? (
              <>
                <button
                  type="button"
                  role="menuitem"
                  className={itemClass}
                  onPointerDown={runAction(() => onSort?.("asc"))}
                >
                  <ArrowUpIcon className="size-3.5" />
                  {locale.columnMenuSortAsc}
                  {sortRule?.direction === "asc" ? (
                    <span className="ml-auto text-[10px] text-muted-foreground">
                      {locale.columnMenuActive}
                    </span>
                  ) : null}
                </button>
                <button
                  type="button"
                  role="menuitem"
                  className={itemClass}
                  onPointerDown={runAction(() => onSort?.("desc"))}
                >
                  <ArrowDownIcon className="size-3.5" />
                  {locale.columnMenuSortDesc}
                  {sortRule?.direction === "desc" ? (
                    <span className="ml-auto text-[10px] text-muted-foreground">
                      {locale.columnMenuActive}
                    </span>
                  ) : null}
                </button>
                {sortRule ? (
                  <button
                    type="button"
                    role="menuitem"
                    className={itemClass}
                    onPointerDown={runAction(() => onSort?.(null))}
                  >
                    {locale.columnMenuClearSort}
                  </button>
                ) : null}
                <div className="my-1 h-px bg-border" />
              </>
            ) : null}

            <button
              type="button"
              role="menuitem"
              className={itemClass}
              onPointerDown={runAction(() =>
                onPin?.(pinned === "left" ? null : "left"),
              )}
            >
              {pinned === "left" ? (
                <PinOffIcon className="size-3.5" />
              ) : (
                <PinIcon className="size-3.5" />
              )}
              {pinned === "left"
                ? locale.columnMenuUnpin
                : locale.columnMenuPinLeft}
            </button>
            <button
              type="button"
              role="menuitem"
              className={itemClass}
              onPointerDown={runAction(() =>
                onPin?.(pinned === "right" ? null : "right"),
              )}
            >
              {pinned === "right" ? (
                <PinOffIcon className="size-3.5" />
              ) : (
                <PinIcon className="size-3.5 rotate-90" />
              )}
              {pinned === "right"
                ? locale.columnMenuUnpin
                : locale.columnMenuPinRight}
            </button>

            <div className="my-1 h-px bg-border" />

            <button
              type="button"
              role="menuitem"
              className={itemClass}
              onPointerDown={runAction(() => onHide?.())}
            >
              <EyeOffIcon className="size-3.5" />
              {locale.columnMenuHide}
            </button>
          </div>
        </FloatingPortal>
      ) : null}
    </>
  );
}

"use client";

import { ChevronDownIcon, Columns3Icon, SearchIcon } from "lucide-react";
import * as React from "react";
import {
  FloatingPortal,
  autoUpdate,
  flip,
  offset,
  shift,
  useClick,
  useDismiss,
  useFloating,
  useInteractions,
  useRole,
} from "@floating-ui/react";

import { Checkbox } from "./components/ui/checkbox";
import { cn } from "./lib/utils";
import { useDataTableLocale } from "./locale-text";
import { toolbarSelectTriggerClass } from "./toolbar-control";
import type { DataTableColumn, DataTableColumnVisibility } from "./types";

export type ColumnVisibilityMenuProps<T> = {
  columns: DataTableColumn<T>[];
  visibility: DataTableColumnVisibility;
  onVisibilityChange: (next: DataTableColumnVisibility) => void;
  radiusClass?: string;
  className?: string;
  /** Floating-ui offset from the trigger. */
  popoverOffset?: number;
};

export function ColumnVisibilityMenu<T>({
  columns,
  visibility,
  onVisibilityChange,
  radiusClass = "rounded-xs",
  className,
  popoverOffset = 8,
}: ColumnVisibilityMenuProps<T>) {
  const locale = useDataTableLocale();
  const [open, setOpen] = React.useState(false);
  const [query, setQuery] = React.useState("");

  const { refs, floatingStyles, context } = useFloating({
    open,
    onOpenChange: (next) => {
      setOpen(next);
      if (!next) setQuery("");
    },
    placement: "bottom-end",
    whileElementsMounted: autoUpdate,
    middleware: [
      offset(popoverOffset),
      flip({ padding: 8 }),
      shift({ padding: 8 }),
    ],
  });

  const click = useClick(context);
  const dismiss = useDismiss(context);
  const role = useRole(context, { role: "menu" });
  const { getReferenceProps, getFloatingProps } = useInteractions([
    click,
    dismiss,
    role,
  ]);

  const filtered = columns.filter((column) =>
    column.header.toLowerCase().includes(query.trim().toLowerCase()),
  );

  const toggle = (key: string, visible: boolean) => {
    onVisibilityChange({ ...visibility, [key]: visible });
  };

  const showAll = () => {
    const next: DataTableColumnVisibility = { ...visibility };
    for (const column of filtered) next[column.key] = true;
    onVisibilityChange(next);
  };

  const hideAll = () => {
    const next: DataTableColumnVisibility = { ...visibility };
    for (const column of filtered) next[column.key] = false;
    onVisibilityChange(next);
  };

  return (
    <>
      <button
        type="button"
        ref={refs.setReference}
        aria-expanded={open}
        aria-haspopup="menu"
        data-slot="data-table-column-selector"
        data-state={open ? "open" : "closed"}
        className={cn(
          toolbarSelectTriggerClass,
          "min-w-[7.5rem]",
          radiusClass,
          className,
        )}
        {...getReferenceProps()}
      >
        <span className="inline-flex min-w-0 items-center gap-1.5">
          <Columns3Icon className="size-3 opacity-70" aria-hidden="true" />
          <span className="truncate">{locale.columnsLabel}</span>
        </span>
        <ChevronDownIcon className="size-3 opacity-50" aria-hidden="true" />
      </button>

      {open ? (
        <FloatingPortal>
          <div
            ref={refs.setFloating}
            style={floatingStyles}
            data-slot="data-table-column-visibility-menu"
            className={cn(
              "z-50 w-64 border border-input bg-popover p-2 text-popover-foreground shadow-md",
              radiusClass,
            )}
            {...getFloatingProps()}
          >
            <div className="relative mb-2">
              <SearchIcon
                className="pointer-events-none absolute top-1/2 left-2 size-3.5 -translate-y-1/2 text-muted-foreground"
                aria-hidden="true"
              />
              <input
                type="search"
                value={query}
                onChange={(event) => setQuery(event.target.value)}
                placeholder={locale.columnsSearchPlaceholder}
                aria-label={locale.columnsSearchAriaLabel}
                className={cn(
                  "h-7 w-full border border-input bg-transparent py-1 pr-2 pl-8 text-xs outline-none placeholder:text-muted-foreground focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50",
                  radiusClass,
                )}
              />
            </div>

            <div className="mb-1.5 flex items-center justify-between gap-2 px-1">
              <p className="text-[11px] font-medium text-muted-foreground">
                {locale.columnsCount(filtered.length)}
              </p>
              <div className="flex gap-1">
                <button
                  type="button"
                  className="text-[11px] text-muted-foreground hover:text-foreground"
                  onClick={showAll}
                >
                  {locale.columnsShowAll}
                </button>
                <span className="text-[11px] text-muted-foreground">/</span>
                <button
                  type="button"
                  className="text-[11px] text-muted-foreground hover:text-foreground"
                  onClick={hideAll}
                >
                  {locale.columnsHideAll}
                </button>
              </div>
            </div>

            <ul className="data-table-thin-scroll flex max-h-56 flex-col gap-0.5 overflow-auto">
              {filtered.length === 0 ? (
                <li className="px-1 py-3 text-center text-xs text-muted-foreground">
                  {locale.columnsNoMatch}
                </li>
              ) : (
                filtered.map((column) => {
                  const visible = visibility[column.key] !== false;
                  return (
                    <li key={column.key}>
                      <label className="flex cursor-pointer items-center gap-2 px-1 py-1.5 text-xs hover:bg-muted">
                        <Checkbox
                          checked={visible}
                          onCheckedChange={(checked) =>
                            toggle(column.key, checked === true)
                          }
                          aria-label={locale.columnsToggleAria(column.header)}
                        />
                        <span className="truncate">{column.header}</span>
                      </label>
                    </li>
                  );
                })
              )}
            </ul>
          </div>
        </FloatingPortal>
      ) : null}
    </>
  );
}

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { Slot } from "radix-ui";

import { cn } from "../../lib/utils";

const buttonVariants = cva(
  "inline-flex shrink-0 items-center justify-center gap-2 text-sm font-medium whitespace-nowrap transition-all outline-none focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50 aria-invalid:border-destructive aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4",
  {
    variants: {
      variant: {
        default: "bg-accent text-accent-fg hover:brightness-110",
        destructive:
          "bg-transparent text-tertiary hover:bg-card hover:text-primary",
        outline:
          "border-[0.5px] border-border bg-transparent text-primary hover:bg-card",
        secondary:
          "bg-card text-primary hover:brightness-110",
        ghost:
          "hover:bg-card hover:text-primary",
        link: "text-accent underline-offset-4 hover:underline",
      },
      size: {
        default: "h-9 px-4 py-2 has-[>svg]:px-3",
        xs: "h-6 gap-1 px-2 text-xs has-[>svg]:px-1.5 [&_svg:not([class*='size-'])]:size-3",
        sm: "h-8 gap-1.5 px-3 has-[>svg]:px-2.5",
        lg: "h-10 px-6 has-[>svg]:px-4",
        icon: "size-9",
        "icon-xs": "size-6 [&_svg:not([class*='size-'])]:size-3",
        "icon-sm": "size-8",
        "icon-lg": "size-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

const Button = React.forwardRef<
  HTMLButtonElement,
  React.ComponentProps<"button"> &
    VariantProps<typeof buttonVariants> & {
      asChild?: boolean;
    }
>(function Button(
  { className, variant = "default", size = "default", asChild = false, ...props },
  ref,
) {
  const Comp = asChild ? Slot.Root : "button";

  return (
    <Comp
      ref={ref}
      data-slot="button"
      data-variant={variant}
      data-size={size}
      className={cn(buttonVariants({ variant, size, className }))}
      {...props}
    />
  );
});

export { Button, buttonVariants };

import type * as React from "react";
import { CheckIcon } from "lucide-react";
import { Checkbox as CheckboxPrimitive } from "radix-ui";

import { cn } from "../../lib/utils";

function Checkbox({
  className,
  ...props
}: React.ComponentProps<typeof CheckboxPrimitive.Root>) {
  return (
    <CheckboxPrimitive.Root
      data-slot="checkbox"
      className={cn(
        "peer size-4 shrink-0 rounded-[4px] border border-border bg-transparent shadow-xs transition-shadow outline-none focus-visible:border-accent focus-visible:ring-[3px] focus-visible:ring-accent/40 disabled:cursor-not-allowed disabled:opacity-50 data-[state=checked]:border-accent data-[state=checked]:bg-accent data-[state=checked]:text-accent-fg",
        className,
      )}
      {...props}
    >
      <CheckboxPrimitive.Indicator
        data-slot="checkbox-indicator"
        className="grid place-content-center text-current transition-none"
      >
        <CheckIcon className="size-3.5" />
      </CheckboxPrimitive.Indicator>
    </CheckboxPrimitive.Root>
  );
}

export { Checkbox };

"use client";

import type * as React from "react";
import { CheckIcon, ChevronDownIcon, ChevronUpIcon } from "lucide-react";
import { Select as SelectPrimitive } from "radix-ui";

import { cn } from "../../lib/utils";

function Select({
  ...props
}: React.ComponentProps<typeof SelectPrimitive.Root>) {
  return <SelectPrimitive.Root data-slot="select" {...props} />;
}

function SelectGroup({
  ...props
}: React.ComponentProps<typeof SelectPrimitive.Group>) {
  return <SelectPrimitive.Group data-slot="select-group" {...props} />;
}

function SelectValue({
  ...props
}: React.ComponentProps<typeof SelectPrimitive.Value>) {
  return <SelectPrimitive.Value data-slot="select-value" {...props} />;
}

function SelectTrigger({
  className,
  size = "default",
  children,
  ...props
}: React.ComponentProps<typeof SelectPrimitive.Trigger> & {
  size?: "sm" | "default";
}) {
  return (
    <SelectPrimitive.Trigger
      data-slot="select-trigger"
      data-size={size}
      className={cn(
        "flex w-fit items-center justify-between gap-2 rounded-md border border-input bg-transparent px-3 py-2 text-sm whitespace-nowrap shadow-xs transition-[color,box-shadow] outline-none focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:cursor-not-allowed disabled:opacity-50 aria-invalid:border-destructive aria-invalid:ring-destructive/20 data-[placeholder]:text-muted-foreground data-[size=default]:h-9 data-[size=sm]:h-8 *:data-[slot=select-value]:line-clamp-1 *:data-[slot=select-value]:flex *:data-[slot=select-value]:items-center *:data-[slot=select-value]:gap-2 dark:bg-input/30 dark:hover:bg-input/50 dark:aria-invalid:ring-destructive/40 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4 [&_svg:not([class*='text-'])]:text-muted-foreground",
        className,
      )}
      {...props}
    >
      {children}
      <SelectPrimitive.Icon asChild>
        <ChevronDownIcon className="size-4 opacity-50" />
      </SelectPrimitive.Icon>
    </SelectPrimitive.Trigger>
  );
}

function SelectContent({
  className,
  children,
  position = "popper",
  align = "center",
  sideOffset = 8,
  ...props
}: React.ComponentProps<typeof SelectPrimitive.Content>) {
  return (
    <SelectPrimitive.Portal>
      <SelectPrimitive.Content
        data-slot="select-content"
        className={cn(
          "relative z-50 max-h-(--radix-select-content-available-height) min-w-[8rem] origin-(--radix-select-content-transform-origin) overflow-x-hidden overflow-y-auto border bg-popover text-popover-foreground shadow-md data-[side=bottom]:slide-in-from-top-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=closed]:zoom-out-95 data-[state=open]:animate-in data-[state=open]:fade-in-0 data-[state=open]:zoom-in-95",
          position === "popper" &&
            "data-[side=bottom]:translate-y-0 data-[side=left]:-translate-x-1 data-[side=right]:translate-x-1 data-[side=top]:translate-y-0",
          className,
        )}
        position={position}
        align={align}
        sideOffset={sideOffset}
        {...props}
      >
        <SelectScrollUpButton />
        <SelectPrimitive.Viewport
          className={cn(
            "p-1",
            position === "popper" &&
              "w-full min-w-[var(--radix-select-trigger-width)] scroll-my-1",
          )}
        >
          {children}
        </SelectPrimitive.Viewport>
        <SelectScrollDownButton />
      </SelectPrimitive.Content>
    </SelectPrimitive.Portal>
  );
}

function SelectLabel({
  className,
  ...props
}: React.ComponentProps<typeof SelectPrimitive.Label>) {
  return (
    <SelectPrimitive.Label
      data-slot="select-label"
      className={cn("px-2 py-1.5 text-xs text-muted-foreground", className)}
      {...props}
    />
  );
}

function SelectItem({
  className,
  children,
  ...props
}: React.ComponentProps<typeof SelectPrimitive.Item>) {
  return (
    <SelectPrimitive.Item
      data-slot="select-item"
      className={cn(
        "relative flex w-full cursor-default items-center gap-2 rounded-sm py-1.5 pr-8 pl-2 text-sm outline-hidden select-none focus:bg-accent focus:text-accent-foreground data-[disabled]:pointer-events-none data-[disabled]:opacity-50 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4 [&_svg:not([class*='text-'])]:text-muted-foreground *:[span]:last:flex *:[span]:last:items-center *:[span]:last:gap-2",
        className,
      )}
      {...props}
    >
      <span
        data-slot="select-item-indicator"
        className="absolute right-2 flex size-3.5 items-center justify-center"
      >
        <SelectPrimitive.ItemIndicator>
          <CheckIcon className="size-4" />
        </SelectPrimitive.ItemIndicator>
      </span>
      <SelectPrimitive.ItemText>{children}</SelectPrimitive.ItemText>
    </SelectPrimitive.Item>
  );
}

function SelectSeparator({
  className,
  ...props
}: React.ComponentProps<typeof SelectPrimitive.Separator>) {
  return (
    <SelectPrimitive.Separator
      data-slot="select-separator"
      className={cn("pointer-events-none -mx-1 my-1 h-px bg-border", className)}
      {...props}
    />
  );
}

function SelectScrollUpButton({
  className,
  ...props
}: React.ComponentProps<typeof SelectPrimitive.ScrollUpButton>) {
  return (
    <SelectPrimitive.ScrollUpButton
      data-slot="select-scroll-up-button"
      className={cn(
        "flex cursor-default items-center justify-center py-1",
        className,
      )}
      {...props}
    >
      <ChevronUpIcon className="size-4" />
    </SelectPrimitive.ScrollUpButton>
  );
}

function SelectScrollDownButton({
  className,
  ...props
}: React.ComponentProps<typeof SelectPrimitive.ScrollDownButton>) {
  return (
    <SelectPrimitive.ScrollDownButton
      data-slot="select-scroll-down-button"
      className={cn(
        "flex cursor-default items-center justify-center py-1",
        className,
      )}
      {...props}
    >
      <ChevronDownIcon className="size-4" />
    </SelectPrimitive.ScrollDownButton>
  );
}

export {
  Select,
  SelectContent,
  SelectGroup,
  SelectItem,
  SelectLabel,
  SelectScrollDownButton,
  SelectScrollUpButton,
  SelectSeparator,
  SelectTrigger,
  SelectValue,
};

import * as React from "react";

import { cn } from "../../lib/utils";

function Table({ className, ...props }: React.ComponentProps<"table">) {
  return (
    <table
      data-slot="table"
      className={cn(
        "w-full caption-bottom border-separate border-spacing-0 text-sm",
        className,
      )}
      {...props}
    />
  );
}

function TableHeader({ className, ...props }: React.ComponentProps<"thead">) {
  return (
    <thead data-slot="table-header" className={cn(className)} {...props} />
  );
}

function TableBody({ className, ...props }: React.ComponentProps<"tbody">) {
  return (
    <tbody data-slot="table-body" className={cn(className)} {...props} />
  );
}

function TableFooter({ className, ...props }: React.ComponentProps<"tfoot">) {
  return (
    <tfoot
      data-slot="table-footer"
      className={cn("bg-muted/40 font-medium", className)}
      {...props}
    />
  );
}

function TableRow({ className, ...props }: React.ComponentProps<"tr">) {
  return (
    <tr
      data-slot="table-row"
      className={cn(
        "transition-colors hover:bg-muted/25 has-aria-expanded:bg-muted/25 data-[state=selected]:bg-muted/40 data-[state=active]:bg-accent/40",
        className,
      )}
      {...props}
    />
