function matchesQuickFilter<T>(
  row: T,
  query: string,
  columns: { key: string }[],
): boolean {
  const q = query.trim().toLowerCase();
  if (!q) return true;
  return columns.some((column) => {
    const value = getCellValue(row, column.key);
    return String(value ?? "")
      .toLowerCase()
      .includes(q);
  });
}

function defaultGetRowId<T>(row: T, index: number): string {
  if (
    row !== null &&
    typeof row === "object" &&
    "id" in row &&
    (typeof (row as { id: unknown }).id === "string" ||
      typeof (row as { id: unknown }).id === "number")
  ) {
    return String((row as { id: string | number }).id);
  }
  return String(index);
}

function getCellValue<T>(row: T, key: string): unknown {
  if (row !== null && typeof row === "object" && key in row) {
    return (row as Record<string, unknown>)[key];
  }
  return undefined;
}

function compareValues(a: unknown, b: unknown): number {
  if (a == null && b == null) return 0;
  if (a == null) return -1;
  if (b == null) return 1;
  if (typeof a === "number" && typeof b === "number") return a - b;
  return String(a).localeCompare(String(b), undefined, {
    numeric: true,
    sensitivity: "base",
  });
}

function matchesFilters<T>(row: T, filters: DataTableFilters): boolean {
  return Object.entries(filters).every(([key, raw]) => {
    const query = String(raw ?? "").trim().toLowerCase();
    if (!query) return true;
    const value = getCellValue(row, key);
    return String(value ?? "")
      .toLowerCase()
      .includes(query);
  });
}

function sortRows<T>(rows: T[], sort: DataTableSort[]): T[] {
  if (sort.length === 0) return rows;

  return [...rows].sort((a, b) => {
    for (const rule of sort) {
      const result = compareValues(
        getCellValue(a, rule.key),
        getCellValue(b, rule.key),
      );
      if (result !== 0) {
        return rule.direction === "asc" ? result : -result;
      }
    }
    return 0;
  });
}

export function DataTable<T>({
  data,
  columns,
  showPagination = true,
  pageSize: pageSizeProp = 10,
  pageSizeOptions,
  paginationMode,
  paginationOptions,
  selectable = false,
  sn = true,
  snHeader,
  stickyHeader = false,
  stickyHeading = false,
  stickyFirstColumn = false,
  minTableWidth,
  maxHeight,
  emptyMessage,
  getRowId = defaultGetRowId,
  selectedIds,
  defaultSelectedIds,
  onSelectionChange,
  enableMultiSort = true,
  sort: controlledSort,
  defaultSort = [],
  onSortChange,
  enableFiltering = false,
  filters: controlledFilters,
  defaultFilters = {},
  onFiltersChange,
  showFilterBuilder = false,
  advancedFilters: controlledAdvancedFilters,
  defaultAdvancedFilters,
  onAdvancedFiltersChange,
  onFilterBuilderApply,
  enableQuickFilter = false,
  quickFilter: controlledQuickFilter,
  defaultQuickFilter = "",
  onQuickFilterChange,
  quickFilterPlaceholder,
  columnVisibility: controlledVisibility,
  defaultColumnVisibility = {},
  onColumnVisibilityChange,
  showColumnSelector = false,
  reorderable = false,
  columnOrder: controlledOrder,
  defaultColumnOrder = [],
  onColumnOrderChange,
  pinnedColumns: controlledPinned,
  defaultPinnedColumns = {},
  onPinnedColumnsChange,
  showColumnMenu = false,
  resizable = false,
  columnWidths,
  defaultColumnWidths,
  onColumnWidthsChange,
  density: controlledDensity,
  defaultDensity = "compact",
  onDensityChange,
  showDensityControl = false,
  activeRowId = null,
  onRowClick,
  className,
  style,
  classNames,
  styles,
  rowClassName,
  radius = "xs",
  mode = "client",
  totalRows,
  loading = false,
  onStateChange,
  popoverOffset = 8,
  popoverPlacement = "bottom-start",
  actions,
  actionsDisplay,
  actionsOptions,
  renderRowActions,
  showRowBorders = true,
  showColumnBorders = false,
  enableVirtualization = false,
  virtualRowHeight,
  virtualOverscan = 8,
  editable = false,
  editMode = "cell",
  editAllColumns = false,
  processRowUpdate,
  onProcessRowUpdateError,
  onCellEditStart,
  onCellEditStop,
  isCellEditable,
  showExport = false,
  exportFilename = "table-export.csv",
  exportScope = "filtered",
  onExported,
  enableKeyboardNavigation = false,
  getDetailPanelContent,
  detailPanelExpandedRowIds: controlledDetailExpanded,
  defaultDetailPanelExpandedRowIds = [],
  onDetailPanelExpandedRowIdsChange,
  treeData = false,
  getTreeDataPath,
  expandedTreeIds: controlledTreeExpanded,
  defaultExpandedTreeIds,
  onExpandedTreeIdsChange,
  defaultGroupingExpansionDepth = 1,
  groupingColDef,
  localeText: localeTextProp,
  toolbar,
}: DataTableProps<T>) {
  const locale = React.useMemo(
    () => resolveLocaleText(localeTextProp),
    [localeTextProp],
  );
  const resolvedEmptyMessage = emptyMessage ?? locale.emptyMessage;
  const resolvedSnHeader = snHeader ?? locale.snHeader;
  const resolvedQuickFilterPlaceholder =
    quickFilterPlaceholder ?? locale.quickFilterPlaceholder;
  const showDetailExpand = typeof getDetailPanelContent === "function";
  const treeEnabled = treeData && typeof getTreeDataPath === "function";
  const virtualizationAllowed =
    enableVirtualization && !showDetailExpand && !treeEnabled;

  const resolvedMode = paginationMode ?? mode;
  const isServer = resolvedMode === "server";
  const radiusClass = RADIUS_CLASS[radius];
  const resolvedActionsDisplay =
    actionsDisplay ?? actionsOptions?.display ?? "menu";
  const actionsSticky = actionsOptions?.sticky ?? true;
  const showRowEditControls = editable && editMode === "row";
  const showActions =
    actions != null ||
    typeof renderRowActions === "function" ||
    showRowEditControls;
  const actionsColumnWidth =
    !showActions
      ? 0
      : typeof renderRowActions === "function" && actions == null
        ? 40
        : resolvedActionsDisplay === "icons"
          ? 108
          : 40;
  const stickyHeaderEnabled = stickyHeader || stickyHeading;
  const resolvedMaxHeight =
    maxHeight ??
    (stickyHeaderEnabled || virtualizationAllowed ? "28rem" : undefined);
  const showFilterBar =
    enableFiltering && columns.some((column) => column.filterable);
  const showToolbar =
    showDensityControl ||
    showColumnSelector ||
    enableQuickFilter ||
    showFilterBuilder ||
    showExport ||
    toolbar != null;

  const [page, setPage] = React.useState(1);
  const [pageSize, setPageSize] = React.useState(pageSizeProp);
  const resolvedPageSizeOptions = React.useMemo(
    () =>
      mergePageSizeOptions(
        paginationOptions?.pageSizeOptions ?? pageSizeOptions,
        pageSize,
      ),
    [pageSize, pageSizeOptions, paginationOptions?.pageSizeOptions],
  );
  const [uncontrolledSort, setUncontrolledSort] = React.useState<DataTableSort[]>(
    normalizeSort(defaultSort),
  );
  const [uncontrolledFilters, setUncontrolledFilters] =
    React.useState<DataTableFilters>(defaultFilters);
  const [uncontrolledAdvancedFilters, setUncontrolledAdvancedFilters] =
    React.useState<FilterCondition[]>(defaultAdvancedFilters ?? []);
  const [uncontrolledDensity, setUncontrolledDensity] =
    React.useState<DataTableDensity>(defaultDensity);
  const [uncontrolledQuickFilter, setUncontrolledQuickFilter] =
    React.useState(defaultQuickFilter);
  const [uncontrolledVisibility, setUncontrolledVisibility] =
    React.useState<DataTableColumnVisibility>(defaultColumnVisibility);
  const [uncontrolledOrder, setUncontrolledOrder] =
    React.useState<string[]>(defaultColumnOrder);
  const [uncontrolledPinned, setUncontrolledPinned] =
    React.useState<DataTablePinnedColumns>(defaultPinnedColumns);
  const [uncontrolledDetailExpanded, setUncontrolledDetailExpanded] =
    React.useState<string[]>(defaultDetailPanelExpandedRowIds);
  const [uncontrolledTreeExpanded, setUncontrolledTreeExpanded] =
    React.useState<string[]>(defaultExpandedTreeIds ?? []);
  const [treeExpandSeeded, setTreeExpandSeeded] = React.useState(
    () => defaultExpandedTreeIds != null,
  );
  const [draggingKey, setDraggingKey] = React.useState<string | null>(null);
  const [scrollElement, setScrollElement] = React.useState<HTMLDivElement | null>(
    null,
  );

  const isSortControlled = controlledSort !== undefined;
  const isFiltersControlled = controlledFilters !== undefined;
  const isAdvancedFiltersControlled = controlledAdvancedFilters !== undefined;
  const isDensityControlled = controlledDensity !== undefined;
  const isQuickFilterControlled = controlledQuickFilter !== undefined;
  const isVisibilityControlled = controlledVisibility !== undefined;
  const isOrderControlled = controlledOrder !== undefined;
  const isPinnedControlled = controlledPinned !== undefined;
  const isDetailExpandedControlled = controlledDetailExpanded !== undefined;
  const isTreeExpandedControlled = controlledTreeExpanded !== undefined;

  const sort = isSortControlled
    ? normalizeSort(controlledSort)
    : uncontrolledSort;
  const filters = isFiltersControlled
    ? controlledFilters
    : uncontrolledFilters;
  const advancedFilters = isAdvancedFiltersControlled
    ? controlledAdvancedFilters
    : uncontrolledAdvancedFilters;
  const density = isDensityControlled
    ? controlledDensity
    : uncontrolledDensity;
  const quickFilter = isQuickFilterControlled
    ? controlledQuickFilter
    : uncontrolledQuickFilter;
  const columnVisibility = isVisibilityControlled
    ? controlledVisibility
    : uncontrolledVisibility;
  const columnOrder = isOrderControlled ? controlledOrder : uncontrolledOrder;
  const pinnedColumns = isPinnedControlled
    ? controlledPinned
    : uncontrolledPinned;
  const detailExpandedIds = isDetailExpandedControlled
    ? controlledDetailExpanded
    : uncontrolledDetailExpanded;
  const expandedTreeIdList = isTreeExpandedControlled
    ? controlledTreeExpanded
    : uncontrolledTreeExpanded;
  const expandedTreeIdSet = React.useMemo(
    () => new Set(expandedTreeIdList),
    [expandedTreeIdList],
  );
  const detailExpandedSet = React.useMemo(
    () => new Set(detailExpandedIds),
    [detailExpandedIds],
  );

  const visibleColumns = React.useMemo(() => {
    const ordered = orderColumns(columns, columnOrder);
    const visible = getVisibleColumns(ordered, columnVisibility);
    return applyPinOrder(visible, pinnedColumns);
  }, [columnOrder, columnVisibility, columns, pinnedColumns]);

  const leftPinnedKeys = React.useMemo(() => {
    const keys: string[] = [];
    for (const column of visibleColumns) {
      const side = resolvePinnedSide(
        column.key,
        pinnedColumns,
        column.pinned ?? (column.sticky ? "left" : undefined),
      );
      if (side === "left") keys.push(column.key);
    }
    return keys;
  }, [pinnedColumns, visibleColumns]);

  const rightPinnedKeys = React.useMemo(() => {
    const keys: string[] = [];
    for (const column of visibleColumns) {
      const side = resolvePinnedSide(
        column.key,
        pinnedColumns,
        column.pinned ?? (column.sticky ? "left" : undefined),
      );
      if (side === "right") keys.push(column.key);
    }
    return keys;
  }, [pinnedColumns, visibleColumns]);

  const rowBorderClass = showRowBorders
    ? "border-b border-black/[0.06] dark:border-white/[0.08]"
    : "border-b-0";
  const columnBorderClass = showColumnBorders
    ? "border-r border-black/[0.06] dark:border-white/[0.08]"
    : "border-r-0";
  const cellBorderClass = cn(rowBorderClass, columnBorderClass);

  const densityCell = DENSITY_CELL_CLASS[density];
  const densityHeader = DENSITY_HEADER_CLASS[density];

  const selection = useTableSelection({
    selectedIds,
    defaultSelectedIds,
    onSelectionChange,
  });

  const editing = useTableEditing<T>({
    editMode,
    getRowId,
    processRowUpdate,
    onProcessRowUpdateError,
    onCellEditStart,
    onCellEditStop,
    isCellEditable,
  });

  const isColumnEditable = React.useCallback(
    (column: DataTableColumn<T>) => {
      if (!editable) return false;
      if (editAllColumns) return column.editable !== false;
      return column.editable === true;
    },
    [editAllColumns, editable],
  );

  const resize = useColumnResize({
    columns: visibleColumns,
    enabled: resizable,
    columnWidths,
    defaultColumnWidths,
    onColumnWidthsChange,
  });

  const getColumnWidthPx = React.useCallback(
    (column: (typeof visibleColumns)[number]) =>
      resizable
        ? resize.getWidth(column.key, column)
        : (column.width ?? column.minWidth ?? 160),
    [resizable, resize],
  );

  const getPinnedLeftOffset = React.useCallback(
    (key: string) => {
      let left = selectable ? 40 : 0;
      left += showDetailExpand ? DETAIL_EXPAND_COLUMN_WIDTH : 0;
      left += sn ? SN_COLUMN_WIDTH : 0;
      for (const pinnedKey of leftPinnedKeys) {
        if (pinnedKey === key) return left;
        const column = visibleColumns.find((item) => item.key === pinnedKey);
        left += column ? getColumnWidthPx(column) : 160;
      }
      return left;
    },
    [
      getColumnWidthPx,
      leftPinnedKeys,
      selectable,
      showDetailExpand,
      sn,
      visibleColumns,
    ],
  );

  const getPinnedRightOffset = React.useCallback(
    (key: string) => {
      let right = showActions ? actionsColumnWidth : 0;
      for (let i = rightPinnedKeys.length - 1; i >= 0; i -= 1) {
        const pinnedKey = rightPinnedKeys[i]!;
        if (pinnedKey === key) return right;
        const column = visibleColumns.find((item) => item.key === pinnedKey);
        right += column ? getColumnWidthPx(column) : 160;
      }
      return right;
    },
    [
      actionsColumnWidth,
      getColumnWidthPx,
      rightPinnedKeys,
      showActions,
      visibleColumns,
    ],
  );

  const emitState = React.useCallback(
    (next: Partial<DataTableState>) => {
      onStateChange?.({
        page,
        pageSize,
        sort,
        filters,
        density,
        columnWidths: resize.widths,
        columnVisibility,
        columnOrder,
        pinnedColumns,
        quickFilter,
        advancedFilters,
        ...next,
      });
    },
    [
      advancedFilters,
      columnOrder,
      columnVisibility,
      density,
      filters,
      onStateChange,
      page,
      pageSize,
      pinnedColumns,
      quickFilter,
      resize.widths,
      sort,
    ],
  );

  React.useEffect(() => {
    setPageSize(pageSizeProp);
    setPage(1);
  }, [pageSizeProp]);

  const processedData = React.useMemo(() => {
    if (isServer) return data;

    let rows = data;

    if (enableFiltering) {
      rows = rows.filter((row) => matchesFilters(row, filters));
    }

    if (showFilterBuilder && advancedFilters.length > 0) {
      rows = rows.filter((row) =>
        matchesFilterConditions(row, advancedFilters, getCellValue),
      );
    }

    if (enableQuickFilter && quickFilter.trim()) {
      rows = rows.filter((row) =>
        matchesQuickFilter(row, quickFilter, visibleColumns),
      );
    }

    return sortRows(rows, sort);
  }, [
    advancedFilters,
    data,
    enableFiltering,
    enableQuickFilter,
    filters,
    isServer,
    quickFilter,
    showFilterBuilder,
    sort,
    visibleColumns,
  ]);

  const totalItemsBase = isServer
    ? (totalRows ?? data.length)
    : processedData.length;

  const treeRoot = React.useMemo(() => {
    if (!treeEnabled || !getTreeDataPath) return null;
    const source = isServer ? data : processedData;
    return buildTreeFromPaths({
      rows: source,
      getTreeDataPath,
      getRowId,
    });
  }, [data, getRowId, getTreeDataPath, isServer, processedData, treeEnabled]);

  React.useEffect(() => {
    if (
      !treeEnabled ||
      !treeRoot ||
      treeExpandSeeded ||
      isTreeExpandedControlled
    ) {
      return;
    }
    setUncontrolledTreeExpanded(
      getDefaultExpandedGroupIds(treeRoot, defaultGroupingExpansionDepth),
    );
    setTreeExpandSeeded(true);
  }, [
    defaultGroupingExpansionDepth,
    isTreeExpandedControlled,
    treeEnabled,
    treeExpandSeeded,
    treeRoot,
  ]);

  const flattenedTreeRows = React.useMemo(() => {
    if (!treeRoot) return null;
    return flattenVisibleTree(treeRoot, { expandedIds: expandedTreeIdSet });
  }, [expandedTreeIdSet, treeRoot]);

  const totalItems =
    treeEnabled && flattenedTreeRows
      ? isServer
        ? (totalRows ?? flattenedTreeRows.length)
        : flattenedTreeRows.length
      : totalItemsBase;
  const pageCount = Math.max(1, Math.ceil(totalItems / pageSize) || 1);

  React.useEffect(() => {
    if (page > pageCount) setPage(pageCount);
  }, [page, pageCount]);

  const pageRows = React.useMemo((): Array<{
    row: T;
    index: number;
    id: string;
    tree?: TreeFlatRow<T>;
  }> => {
    type PageRow = {
      row: T;
      index: number;
      id: string;
      tree?: TreeFlatRow<T>;
    };

    if (treeEnabled && flattenedTreeRows) {
      const start = isServer ? 0 : (page - 1) * pageSize;
      const slice = isServer
        ? flattenedTreeRows
        : flattenedTreeRows.slice(start, start + pageSize);

      return slice.map((treeRow, indexOnPage): PageRow => {
        const absoluteIndex = start + indexOnPage;
        if (treeRow.kind === "leaf" && treeRow.row != null) {
          const id = treeRow.id;
          return {
            row: editing.getDisplayRow(treeRow.row, id),
            index: absoluteIndex,
            id,
            tree: treeRow,
          };
        }
        return {
          row: treeRow.row ?? ({} as T),
          index: absoluteIndex,
          id: treeRow.id,
          tree: treeRow,
        };
      });
    }

    if (isServer) {
      return data.map((row, index): PageRow => {
        const id = getRowId(row, index);
        return {
          row: editing.getDisplayRow(row, id),
          index,
          id,
        };
      });
    }

    const start = (page - 1) * pageSize;
    return processedData.slice(start, start + pageSize).map((row, index): PageRow => {
      const absoluteIndex = start + index;
      const id = getRowId(row, absoluteIndex);
      return {
        row: editing.getDisplayRow(row, id),
        index: absoluteIndex,
        id,
      };
    });
  }, [
    data,
    editing.getDisplayRow,
    editing.rowOverrides,
    flattenedTreeRows,
    getRowId,
    isServer,
    page,
    pageSize,
    processedData,
    treeEnabled,
  ]);

  const pageIds = pageRows
    .filter((item) => !item.tree || isSelectableTreeRow(item.tree))
    .map((item) => item.id);
  const allPageSelected = selection.isAllSelected(pageIds);
  const somePageSelected = selection.isSomeSelected(pageIds);

  const virtualization = useTableVirtualization({
    enabled: virtualizationAllowed && pageRows.length > 0 && !loading,
    count: pageRows.length,
    scrollElement,
    density,
    estimateSize: virtualRowHeight,
    overscan: virtualOverscan,
  });

  const setDetailExpanded = React.useCallback(
    (ids: string[]) => {
      if (!isDetailExpandedControlled) setUncontrolledDetailExpanded(ids);
      onDetailPanelExpandedRowIdsChange?.(ids);
    },
    [isDetailExpandedControlled, onDetailPanelExpandedRowIdsChange],
  );

  const toggleDetailExpanded = React.useCallback(
    (id: string) => {
      const next = detailExpandedSet.has(id)
        ? detailExpandedIds.filter((item) => item !== id)
        : [...detailExpandedIds, id];
      setDetailExpanded(next);
    },
    [detailExpandedIds, detailExpandedSet, setDetailExpanded],
  );

  const setTreeExpanded = React.useCallback(
    (ids: string[]) => {
      if (!isTreeExpandedControlled) setUncontrolledTreeExpanded(ids);
      onExpandedTreeIdsChange?.(ids);
    },
    [isTreeExpandedControlled, onExpandedTreeIdsChange],
  );

  const toggleTreeExpanded = React.useCallback(
    (id: string) => {
      const next = expandedTreeIdSet.has(id)
        ? expandedTreeIdList.filter((item) => item !== id)
        : [...expandedTreeIdList, id];
      setTreeExpanded(next);
    },
    [expandedTreeIdList, expandedTreeIdSet, setTreeExpanded],
  );

  const bodyRows = virtualization.enabled
    ? virtualization.virtualRows.map((virtualRow) => ({
        virtualRow,
        ...pageRows[virtualRow.index]!,
        rowIndexOnPage: virtualRow.index,
      }))
    : pageRows.map((item, rowIndexOnPage) => ({
        virtualRow: null,
        ...item,
        rowIndexOnPage,
      }));

  const keyboard = useTableKeyboard({
    enabled: enableKeyboardNavigation && pageRows.length > 0,
    rowCount: pageRows.length,
    colCount: visibleColumns.length,
    editable,
    isEditing:
      editing.editingCell != null || editing.editingRowId != null,
    onStartEdit: ({ rowIndex, colIndex }) => {
      const item = pageRows[rowIndex];
      const column = visibleColumns[colIndex];
      if (!item || !column || item.tree?.kind === "group") return;
      if (!isColumnEditable(column)) return;
      const value = getCellValue(item.row, column.key);
      const params = {
        id: item.id,
        field: column.key,
        row: item.row,
        value,
      };
      if (editMode === "row") editing.startRowEdit(params);
      else editing.startCellEdit(params);
    },
  });

  const getExportCsv = React.useCallback(() => {
    const exportColumns = visibleColumns.map((column) => ({
      key: column.key,
      header: column.header,
    }));

    let exportRows: T[] = [];
    if (exportScope === "page") {
      exportRows = pageRows
        .filter((item) => !item.tree || isSelectableTreeRow(item.tree))
        .map((item) => item.row);
    } else if (exportScope === "selected") {
      const selected = new Set(selection.selectedIds);
      const source = isServer ? data : processedData;
      exportRows = source
        .map((row, index) => ({
          row: editing.getDisplayRow(row, getRowId(row, index)),
          id: getRowId(row, index),
        }))
        .filter((item) => selected.has(item.id))
        .map((item) => item.row);
    } else {
      const source = isServer ? data : processedData;
      exportRows = source.map((row, index) =>
        editing.getDisplayRow(row, getRowId(row, index)),
      );
    }

    return rowsToCsvMatrix({
      columns: exportColumns,
      rows: exportRows,
      getValue: getCellValue,
    });
  }, [
    data,
    editing,
    exportScope,
    getRowId,
    isServer,
    pageRows,
    processedData,
    selection.selectedIds,
    visibleColumns,
  ]);

  const colSpan =
    visibleColumns.length +
    (selectable ? 1 : 0) +
    (showDetailExpand ? 1 : 0) +
    (sn ? 1 : 0) +
    (showActions ? 1 : 0);

  const firstStickyLeft = selectable
    ? showDetailExpand
      ? `${40 + DETAIL_EXPAND_COLUMN_WIDTH}px`
      : "2.5rem"
    : showDetailExpand
      ? `${DETAIL_EXPAND_COLUMN_WIDTH}px`
      : "0";

  const tableMinWidth = React.useMemo(() => {
    if (minTableWidth) return minTableWidth;
    if (!resizable) return undefined;
    const dataWidth = visibleColumns.reduce(
      (sum, column) => sum + resize.getWidth(column.key, column),
      0,
    );
    const extras =
      (selectable ? 40 : 0) +
      (showDetailExpand ? DETAIL_EXPAND_COLUMN_WIDTH : 0) +
      (sn ? SN_COLUMN_WIDTH : 0) +
      (showActions ? actionsColumnWidth : 0);
    return `${dataWidth + extras}px`;
  }, [
    actionsColumnWidth,
    minTableWidth,
    resizable,
    resize,
    selectable,
    showActions,
    showDetailExpand,
    sn,
    visibleColumns,
  ]);

  const handlePageChange = (nextPage: number) => {
    setPage(nextPage);
    emitState({ page: nextPage });
  };

  const handlePageSizeChange = (nextSize: number) => {
    setPageSize(nextSize);
    setPage(1);
    emitState({ page: 1, pageSize: nextSize });
  };

  const handleSort = (key: string) => {
    const resolved = cycleMultiSort(sort, key, {
      replace: !enableMultiSort,
    });

    if (!isSortControlled) setUncontrolledSort(resolved);
    onSortChange?.(resolved);
    setPage(1);
    emitState({ sort: resolved, page: 1 });
  };

  const handleFiltersChange = (next: DataTableFilters) => {
    if (!isFiltersControlled) setUncontrolledFilters(next);
    onFiltersChange?.(next);
    setPage(1);
    emitState({ filters: next, page: 1 });
  };

  const handleFilterBuilderApply = (payload: {
    conditions: FilterCondition[];
    params: URLSearchParams | null;
  }) => {
    const next = payload.params == null ? [] : payload.conditions;
    if (!isAdvancedFiltersControlled) setUncontrolledAdvancedFilters(next);
    onAdvancedFiltersChange?.(next);
    onFilterBuilderApply?.(payload);
    setPage(1);
    emitState({ advancedFilters: next, page: 1 });
  };

  const filterBuilderColumns = React.useMemo(
    () => toFilterBuilderColumns(columns),
    [columns],
  );

  const appliedAdvancedFilterCount = advancedFilters.filter((condition) => {
    const needsValue = !["boolean", "range", "color"].includes(
      filterBuilderColumns.find((column) => column.value === condition.column)
        ?.type ?? "string",
    );
    return needsValue ? condition.value.trim() !== "" : true;
  }).length;

  const handleDensityChange = (next: DataTableDensity) => {
    if (!isDensityControlled) setUncontrolledDensity(next);
    onDensityChange?.(next);
    emitState({ density: next });
  };

  const handleQuickFilterChange = (next: string) => {
    if (!isQuickFilterControlled) setUncontrolledQuickFilter(next);
    onQuickFilterChange?.(next);
    setPage(1);
    emitState({ quickFilter: next, page: 1 });
  };

  const handleVisibilityChange = (next: DataTableColumnVisibility) => {
    if (!isVisibilityControlled) setUncontrolledVisibility(next);
    onColumnVisibilityChange?.(next);
    emitState({ columnVisibility: next });
  };

  const handleOrderChange = (next: string[]) => {
    if (!isOrderControlled) setUncontrolledOrder(next);
    onColumnOrderChange?.(next);
    emitState({ columnOrder: next });
  };

  const handlePinnedChange = (next: DataTablePinnedColumns) => {
    if (!isPinnedControlled) setUncontrolledPinned(next);
    onPinnedColumnsChange?.(next);
    emitState({ pinnedColumns: next });
  };

  const handleHeaderSort = (key: string, direction: SortDirection | null) => {
    let resolved: DataTableSort[];
    if (direction == null) {
      resolved = sort.filter((item) => item.key !== key);
    } else if (enableMultiSort) {
      const without = sort.filter((item) => item.key !== key);
      resolved = [...without, { key, direction }];
    } else {
      resolved = [{ key, direction }];
    }
    if (!isSortControlled) setUncontrolledSort(resolved);
    onSortChange?.(resolved);
    setPage(1);
    emitState({ sort: resolved, page: 1 });
  };

  const handlePinColumn = (key: string, side: "left" | "right" | null) => {
    const left = (pinnedColumns.left ?? []).filter((item) => item !== key);
    const right = (pinnedColumns.right ?? []).filter((item) => item !== key);
    if (side === "left") left.push(key);
    if (side === "right") right.push(key);
    handlePinnedChange({ left, right });
  };

  const handleHideColumn = (key: string) => {
    handleVisibilityChange({ ...columnVisibility, [key]: false });
  };

  const handleDropReorder = (targetKey: string) => {
    if (!reorderable || !draggingKey || draggingKey === targetKey) return;
    const currentOrder =
      columnOrder.length > 0
        ? [...columnOrder]
        : columns.map((column) => column.key);
    const from = currentOrder.indexOf(draggingKey);
    const to = currentOrder.indexOf(targetKey);
    if (from < 0 || to < 0) return;
    currentOrder.splice(from, 1);
    currentOrder.splice(to, 0, draggingKey);
    handleOrderChange(currentOrder);
    setDraggingKey(null);
  };

  const handleSelectAll = (checked: boolean | "indeterminate") => {
    if (checked === true) {
      selection.selectAll(
        Array.from(new Set([...selection.selectedIds, ...pageIds])),
      );
      return;
    }
    selection.selectAll(
      selection.selectedIds.filter((id) => !pageIds.includes(id)),
    );
  };

  return (
    <DataTableLocaleProvider value={locale}>
    <div
      data-slot="data-table"
      data-density={density}
      data-radius={radius}
      data-mode={resolvedMode}
      data-sticky-header={stickyHeaderEnabled ? "true" : "false"}
      data-resizable={resizable ? "true" : "false"}
      data-tree={treeEnabled ? "true" : "false"}
      data-detail-panel={showDetailExpand ? "true" : "false"}
      style={{ ...styles?.root, ...style }}
      className={cn(
        "w-full overflow-hidden bg-card text-card-foreground shadow-[0_1px_3px_rgba(0,0,0,0.06)] ring-1 ring-black/[0.04] dark:shadow-[0_1px_3px_rgba(0,0,0,0.35)] dark:ring-white/8",
        radiusClass,
        resize.isResizing && "select-none",
        classNames?.root,
        className,
      )}
    >
      {showToolbar ? (
        <div
          data-slot="data-table-toolbar"
          className={cn(
            "flex flex-wrap items-center gap-1.5 border-b border-black/[0.04] px-3 py-2 dark:border-white/[0.06]",
            classNames?.toolbar,
          )}
          style={styles?.toolbar}
        >
          {enableQuickFilter ? (
            <QuickFilter
              value={quickFilter}
              onChange={handleQuickFilterChange}
              placeholder={resolvedQuickFilterPlaceholder}
              radiusClass={radiusClass}
              className={classNames?.quickFilter}
            />
          ) : null}

          <div className="min-w-0 flex-1">{toolbar}</div>

          <div className="ml-auto flex flex-wrap items-center gap-1.5">
            {showFilterBuilder ? (
              <FilterBuilderMenu
                columns={filterBuilderColumns}
                applied={advancedFilters}
                onApply={handleFilterBuilderApply}
                onClear={() =>
                  handleFilterBuilderApply({ conditions: [], params: null })
                }
                activeCount={appliedAdvancedFilterCount}
                radiusClass={radiusClass}
                className={classNames?.filterBuilder}
              />
            ) : null}
            {showExport ? (
              <ExportMenu
                getCsv={getExportCsv}
                filename={exportFilename}
                radiusClass={radiusClass}
                className={classNames?.export}
                onExported={onExported}
              />
            ) : null}
            {showColumnSelector ? (
              <ColumnVisibilityMenu
                columns={columns}
                visibility={columnVisibility}
                onVisibilityChange={handleVisibilityChange}
                radiusClass={radiusClass}
                className={classNames?.columnSelector}
              />
            ) : null}
            {showDensityControl ? (
              <DensityControl
                value={density}
                onChange={handleDensityChange}
                radiusClass={radiusClass}
                className={classNames?.densityControl}
              />
            ) : null}
          </div>
        </div>
      ) : null}

      {showFilterBar ? (
        <FilterBar
          columns={visibleColumns}
          filters={filters}
          onFiltersChange={handleFiltersChange}
          className={classNames?.filterBar}
          radiusClass={radiusClass}
          style={styles?.filterBar}
        />
      ) : null}

      <div
        ref={setScrollElement}
        data-slot="data-table-scroll"
        data-virtualized={virtualization.enabled ? "true" : "false"}
        className={cn(
          "data-table-thin-scroll relative w-full overflow-auto overscroll-x-contain [scrollbar-width:thin] [&::-webkit-scrollbar]:h-1.5 [&::-webkit-scrollbar]:w-1.5 [&::-webkit-scrollbar-thumb]:rounded-full [&::-webkit-scrollbar-thumb]:bg-black/15 dark:[&::-webkit-scrollbar-thumb]:bg-white/20 [&::-webkit-scrollbar-track]:bg-transparent",
          classNames?.scroll,
        )}
        style={{
          ...(resolvedMaxHeight ? { maxHeight: resolvedMaxHeight } : null),
          ...styles?.scroll,
        }}
      >
        {loading ? (
          <div
            data-slot="data-table-loading"
            className={cn(
              "absolute inset-0 z-30 flex items-center justify-center bg-background/60 backdrop-blur-[1px]",
              classNames?.loading,
            )}
            style={styles?.loading}
            aria-live="polite"
            aria-busy="true"
          >
            <span className="text-sm text-muted-foreground">{locale.loading}</span>
          </div>
        ) : null}

        <Table
          className={cn(
            "min-w-full",
            (resizable ||
              visibleColumns.some((c) => c.width || c.maxWidth)) &&
              "table-fixed",
            classNames?.table,
          )}
          style={{
            ...(tableMinWidth ? { minWidth: tableMinWidth } : null),
            ...styles?.table,
          }}
        >
          {resizable ||
          visibleColumns.some((c) => c.width || c.minWidth) ||
          sn ||
          showDetailExpand ? (
            <colgroup>
              {selectable ? <col style={{ width: 40 }} /> : null}
              {showDetailExpand ? (
                <col style={{ width: DETAIL_EXPAND_COLUMN_WIDTH }} />
              ) : null}
              {sn ? (
                <col
                  style={{
                    width: SN_COLUMN_WIDTH,
                    minWidth: SN_COLUMN_WIDTH,
                    maxWidth: SN_COLUMN_WIDTH,
                  }}
                />
              ) : null}
              {visibleColumns.map((column) => {
                const width = resizable
                  ? resize.getWidth(column.key, column)
                  : column.key === visibleColumns[0]?.key &&
                      groupingColDef?.width != null
                    ? groupingColDef.width
                    : column.width;
                return (
                  <col
                    key={column.key}
                    style={{
                      width,
                      minWidth: column.minWidth,
                      maxWidth: column.maxWidth,
                    }}
                  />
                );
              })}
              {showActions ? (
                <col style={{ width: actionsColumnWidth }} />
              ) : null}
            </colgroup>
          ) : null}

          <TableHeader
            className={cn(
              stickyHeaderEnabled &&
                "sticky top-0 z-20 bg-card shadow-[0_1px_0_0_rgba(0,0,0,0.04)] dark:shadow-[0_1px_0_0_rgba(255,255,255,0.06)]",
              classNames?.header,
            )}
            style={styles?.header}
          >
            <TableRow
              data-state="header"
              className={cn("hover:bg-transparent", classNames?.headerRow)}
              style={styles?.headerRow}
            >
              {selectable ? (
                <TableHead
                  className={cn(
                    "w-10 bg-card",
                    densityHeader,
                    cellBorderClass,
                    (stickyFirstColumn || leftPinnedKeys.length > 0) &&
                      "sticky left-0 z-40",
                    classNames?.headerCell,
                  )}
                >
                  <Checkbox
                    checked={
                      allPageSelected
                        ? true
                        : somePageSelected
                          ? "indeterminate"
                          : false
                    }
                    onCheckedChange={handleSelectAll}
                    aria-label={locale.selectAllAria}
                  />
                </TableHead>
              ) : null}

              {showDetailExpand ? (
                <TableHead
                  className={cn(
                    "w-9 bg-card",
                    densityHeader,
                    cellBorderClass,
                    classNames?.headerCell,
                  )}
                  style={{ width: DETAIL_EXPAND_COLUMN_WIDTH }}
                >
                  <span className="sr-only">{locale.detailPanelAria}</span>
                </TableHead>
              ) : null}

              {sn ? (
                <SnHeader
                  label={resolvedSnHeader}
                  className={cn(
                    cellBorderClass,
                    (stickyFirstColumn || leftPinnedKeys.length > 0) &&
                      "sticky z-40",
                    classNames?.headerCell,
                  )}
                  style={
                    stickyFirstColumn || leftPinnedKeys.length > 0
                      ? {
                          left:
                            (selectable ? 40 : 0) +
                            (showDetailExpand
                              ? DETAIL_EXPAND_COLUMN_WIDTH
                              : 0),
                        }
                      : undefined
                  }
                />
              ) : null}

              {visibleColumns.map((column, columnIndex) => {
                const sortIndex = sort.findIndex(
                  (item) => item.key === column.key,
                );
                const sortRule = sortIndex >= 0 ? sort[sortIndex] : undefined;
                const pinnedSide = resolvePinnedSide(
                  column.key,
                  pinnedColumns,
                  column.pinned ?? (column.sticky ? "left" : undefined),
                );
                const isSticky =
                  pinnedSide === "left" ||
                  pinnedSide === "right" ||
                  (stickyFirstColumn && columnIndex === 0);
                const canResize =
                  resizable && column.resizable !== false;
                const resizedWidth = resizable
                  ? resize.getWidth(column.key, column)
                  : undefined;
                const sizeStyle = getColumnSizeStyle(column, resizedWidth);
                const truncate = shouldTruncateColumn(column);
                const isLastLeftPin =
                  pinnedSide === "left" &&
                  leftPinnedKeys[leftPinnedKeys.length - 1] === column.key;
                const isFirstRightPin =
                  pinnedSide === "right" &&
                  rightPinnedKeys[0] === column.key;
                const pinnedLeft =
                  pinnedSide === "left"
                    ? getPinnedLeftOffset(column.key)
                    : stickyFirstColumn && columnIndex === 0
                      ? firstStickyLeft
                      : undefined;
                const pinnedRight =
                  pinnedSide === "right"
                    ? getPinnedRightOffset(column.key)
                    : undefined;

                return (
                  <TableHead
                    key={column.key}
                    draggable={reorderable}
                    onDragStart={() => setDraggingKey(column.key)}
                    onDragOver={(event) => {
                      if (!reorderable) return;
                      event.preventDefault();
                    }}
                    onDrop={() => handleDropReorder(column.key)}
                    onDragEnd={() => setDraggingKey(null)}
                    className={cn(
                      "relative overflow-hidden bg-card",
                      densityHeader,
                      cellBorderClass,
                      column.hideBelow && HIDE_BELOW_CLASS[column.hideBelow],
                      isSticky && "sticky z-30",
                      isLastLeftPin &&
                        "shadow-[1px_0_0_0_rgba(0,0,0,0.08)] dark:shadow-[1px_0_0_0_rgba(255,255,255,0.1)]",
                      isFirstRightPin &&
                        "shadow-[-1px_0_0_0_rgba(0,0,0,0.08)] dark:shadow-[-1px_0_0_0_rgba(255,255,255,0.1)]",
                      draggingKey === column.key && "opacity-50",
                      reorderable && "cursor-grab active:cursor-grabbing",
                      column.headerClassName,
                      classNames?.headerCell,
                    )}
                    style={{
                      ...sizeStyle,
                      ...(pinnedLeft != null ? { left: pinnedLeft } : null),
                      ...(pinnedRight != null ? { right: pinnedRight } : null),
                    }}
                    aria-sort={
                      column.sortable
                        ? sortRule?.direction === "asc"
                          ? "ascending"
                          : sortRule?.direction === "desc"
                            ? "descending"
                            : "none"
                        : undefined
                    }
                  >
                    <div
                      className={cn(
                        "flex min-w-0 items-center gap-1",
                        canResize && "pr-2",
                      )}
                    >
                      {column.sortable ? (
                        <button
                          type="button"
                          className="inline-flex min-w-0 max-w-full items-center gap-1.5 outline-none hover:text-foreground focus-visible:ring-[3px] focus-visible:ring-ring/50"
                          onClick={() => handleSort(column.key)}
                          aria-label={locale.sortByAria(
                            columnIndex === 0 && groupingColDef?.headerName
                              ? groupingColDef.headerName
                              : column.header,
                          )}
                          title={
                            columnIndex === 0 && groupingColDef?.headerName
                              ? groupingColDef.headerName
                              : column.header
                          }
                        >
                          <CellContent truncate={truncate} wrap={column.wrap}>
                            {columnIndex === 0 && groupingColDef?.headerName
                              ? groupingColDef.headerName
                              : column.header}
                          </CellContent>
                          {sortRule?.direction === "asc" ? (
                            <ArrowUpIcon
                              className="size-3.5 shrink-0"
                              aria-hidden="true"
                            />
                          ) : sortRule?.direction === "desc" ? (
                            <ArrowDownIcon
                              className="size-3.5 shrink-0"
                              aria-hidden="true"
                            />
                          ) : (
                            <ArrowUpDownIcon
                              className="size-3.5 shrink-0 opacity-40"
                              aria-hidden="true"
                            />
                          )}
                          {sortIndex >= 0 && sort.length > 1 ? (
                            <span
                              className="inline-flex size-4 shrink-0 items-center justify-center bg-muted text-[10px] font-semibold text-muted-foreground"
                              aria-label={locale.sortPriorityAria(sortIndex + 1)}
                            >
                              {sortIndex + 1}
                            </span>
                          ) : null}
                        </button>
                      ) : (
                        <CellContent
                          truncate={truncate}
                          wrap={column.wrap}
                          title={column.header}
                        >
                          {column.header}
                        </CellContent>
                      )}

                      {showColumnMenu ? (
                        <ColumnHeaderMenu
                          columnKey={column.key}
                          header={column.header}
                          sortable={column.sortable}
                          sortRule={sortRule}
                          pinned={pinnedSide}
                          radiusClass={radiusClass}
                          onSort={(direction) =>
                            handleHeaderSort(column.key, direction)
                          }
                          onHide={() => handleHideColumn(column.key)}
                          onPin={(side) => handlePinColumn(column.key, side)}
                        />
                      ) : null}
                    </div>

                    {canResize ? (
                      <div
                        role="separator"
                        aria-orientation="vertical"
                        aria-label={locale.resizeColumnAria(column.header)}
                        tabIndex={0}
                        className="group/resize absolute top-0 right-0 z-40 flex h-full w-2.5 cursor-col-resize touch-none select-none items-center justify-center"
                        onMouseDown={(event) =>
                          resize.beginResize(column.key, event, {
                            minWidth: column.minWidth,
                            maxWidth: column.maxWidth,
                          })
                        }
                        onTouchStart={(event) =>
                          resize.beginResize(column.key, event, {
                            minWidth: column.minWidth,
                            maxWidth: column.maxWidth,
                          })
                        }
                        onKeyDown={(event) => {
                          if (
                            event.key !== "ArrowLeft" &&
                            event.key !== "ArrowRight"
                          ) {
                            return;
                          }
                          event.preventDefault();
                          const delta = event.key === "ArrowRight" ? 8 : -8;
                          const current = resize.getWidth(column.key, column);
                          resize.setWidth(column.key, current + delta, {
                            minWidth: column.minWidth,
                            maxWidth: column.maxWidth,
                          });
                        }}
                        onDoubleClick={(event) => {
                          event.stopPropagation();
                          resize.setWidth(
                            column.key,
                            column.width ?? column.minWidth ?? 160,
                            {
                              minWidth: column.minWidth,
                              maxWidth: column.maxWidth,
                            },
                          );
                        }}
                      >
                        <span className="h-3.5 w-px bg-transparent group-hover/resize:bg-foreground/20 group-focus-visible/resize:bg-foreground/30" />
                      </div>
                    ) : null}
                  </TableHead>
                );
              })}

              {showActions ? (
                <TableHead
                  className={cn(
                    "bg-card",
                    densityHeader,
                    cellBorderClass,
                    actionsSticky &&
                      "sticky right-0 z-30 shadow-[-1px_0_0_0_rgba(0,0,0,0.06)] dark:shadow-[-1px_0_0_0_rgba(255,255,255,0.08)]",
                    classNames?.headerCell,
                  )}
                  style={{
                    width: actionsColumnWidth,
                    minWidth: actionsColumnWidth,
                  }}
                >
                  <span className="sr-only">{locale.actionsHeader}</span>
                </TableHead>
              ) : null}
            </TableRow>
          </TableHeader>

          <TableBody className={classNames?.body} style={styles?.body}>
            {pageRows.length === 0 ? (
              <TableRow className="hover:bg-transparent">
                <TableCell
                  colSpan={colSpan}
                  className={cn(
                    "h-28 text-center text-muted-foreground",
                    densityCell,
                    classNames?.cell,
                    classNames?.empty,
                  )}
                  style={{ ...styles?.cell, ...styles?.empty }}
                >
                  {resolvedEmptyMessage}
                </TableCell>
              </TableRow>
            ) : (
              <>
                {virtualization.enabled && virtualization.paddingTop > 0 ? (
                  <tr aria-hidden="true">
                    <td
                      colSpan={colSpan}
                      style={{
                        height: virtualization.paddingTop,
                        padding: 0,
                        border: 0,
                      }}
                    />
                  </tr>
                ) : null}

                {bodyRows.map(({ row, index, id, rowIndexOnPage, tree }) => {
                const isGroup = tree?.kind === "group";
                const canSelect = !tree || isSelectableTreeRow(tree);
                const isSelected = canSelect && selection.isSelected(id);
                const isActive = activeRowId === id;
                const resolvedRowClassName =
                  typeof rowClassName === "function"
                    ? rowClassName(row, index)
                    : rowClassName;
                const detailContent =
                  !isGroup && showDetailExpand && getDetailPanelContent
                    ? getDetailPanelContent({ id, row })
                    : null;
                const canExpandDetail = detailContent != null;
                const detailOpen =
                  canExpandDetail && detailExpandedSet.has(id);

                return (
                  <React.Fragment key={id}>
                  <TableRow
                    data-index={rowIndexOnPage}
                    data-tree-kind={tree?.kind}
                    data-state={
                      isSelected ? "selected" : isActive ? "active" : undefined
                    }
                    className={cn(
                      onRowClick && !isGroup && "cursor-pointer",
                      isGroup && "bg-muted/20 font-medium",
                      classNames?.row,
                      resolvedRowClassName,
                    )}
                    style={styles?.row}
                    onClick={() => {
                      if (isGroup) return;
                      onRowClick?.(row, index);
                    }}
                  >
                    {selectable ? (
                      <TableCell
                        className={cn(
                          "bg-card",
                          densityCell,
                          cellBorderClass,
                          (stickyFirstColumn || leftPinnedKeys.length > 0) &&
                            "sticky left-0 z-20",
                          isSelected && "bg-muted/40",
                          classNames?.cell,
                        )}
                      >
                        {canSelect ? (
                          <Checkbox
                            checked={isSelected}
                            onCheckedChange={() => selection.toggle(id)}
                            aria-label={locale.selectRowAria(id)}
                            onClick={(event) => event.stopPropagation()}
                          />
                        ) : null}
                      </TableCell>
                    ) : null}

                    {showDetailExpand ? (
                      <TableCell
                        className={cn(
                          "bg-card",
                          densityCell,
                          cellBorderClass,
                          isSelected && "bg-muted/40",
                          classNames?.cell,
                        )}
                        style={{ width: DETAIL_EXPAND_COLUMN_WIDTH }}
                      >
                        {canExpandDetail ? (
                          <DetailExpandButton
                            expanded={detailOpen}
                            onToggle={() => toggleDetailExpanded(id)}
                            variant="detail"
                          />
                        ) : null}
                      </TableCell>
                    ) : null}

                    {sn ? (
                      <SnCell
                        value={getSerialNumber(page, pageSize, rowIndexOnPage)}
                        className={cn(
                          cellBorderClass,
                          (stickyFirstColumn || leftPinnedKeys.length > 0) &&
                            "sticky z-20",
                          isSelected && "bg-muted/40",
                          classNames?.cell,
                        )}
                        style={
                          stickyFirstColumn || leftPinnedKeys.length > 0
                            ? {
                                left:
                                  (selectable ? 40 : 0) +
                                  (showDetailExpand
                                    ? DETAIL_EXPAND_COLUMN_WIDTH
                                    : 0),
                              }
                            : undefined
                        }
                      />
                    ) : null}

                    {visibleColumns.map((column, columnIndex) => {
                      const rawValue =
                        isGroup && columnIndex === 0
                          ? (tree?.label ?? "")
                          : isGroup
                            ? ""
                            : getCellValue(row, column.key);
                      const textValue =
                        rawValue == null ? "" : String(rawValue);
                      const content =
                        isGroup && columnIndex === 0
                          ? null
                          : isGroup
                            ? null
                            : column.cell
                              ? column.cell(row, index)
                              : textValue;
                      const pinnedSide = resolvePinnedSide(
                        column.key,
                        pinnedColumns,
                        column.pinned ?? (column.sticky ? "left" : undefined),
                      );
                      const isSticky =
                        pinnedSide === "left" ||
                        pinnedSide === "right" ||
                        (stickyFirstColumn && columnIndex === 0);
                      const resizedWidth = resizable
                        ? resize.getWidth(column.key, column)
                        : undefined;
                      const sizeStyle = getColumnSizeStyle(
                        column,
                        resizedWidth,
                      );
                      const truncate = shouldTruncateColumn(column);
                      const isLastLeftPin =
                        pinnedSide === "left" &&
                        leftPinnedKeys[leftPinnedKeys.length - 1] ===
                          column.key;
                      const isFirstRightPin =
                        pinnedSide === "right" &&
                        rightPinnedKeys[0] === column.key;
                      const pinnedLeft =
                        pinnedSide === "left"
                          ? getPinnedLeftOffset(column.key)
                          : stickyFirstColumn && columnIndex === 0
                            ? firstStickyLeft
                            : undefined;
                      const pinnedRight =
                        pinnedSide === "right"
                          ? getPinnedRightOffset(column.key)
                          : undefined;
                      const canEdit = !isGroup && isColumnEditable(column);
                      const cellEditing =
                        !isGroup &&
                        editing.isEditingCell(id, column.key);
                      const editValue =
                        editing.draft[column.key] !== undefined
                          ? editing.draft[column.key]
                          : rawValue;
                      const keyboardProps =
                        enableKeyboardNavigation && !isGroup
                          ? keyboard.getCellProps(rowIndexOnPage, columnIndex)
                          : null;
                      const showTreeChrome =
                        treeEnabled && columnIndex === 0 && tree != null;

                      return (
                        <TableCell
                          key={column.key}
                          data-table-cell={
                            isGroup
                              ? undefined
                              : `${rowIndexOnPage}:${columnIndex}`
                          }
                          className={cn(
                            "overflow-hidden bg-card",
                            densityCell,
                            cellBorderClass,
                            column.hideBelow &&
                              HIDE_BELOW_CLASS[column.hideBelow],
                            isSticky && "sticky z-10",
                            isLastLeftPin &&
                              "shadow-[1px_0_0_0_rgba(0,0,0,0.08)] dark:shadow-[1px_0_0_0_rgba(255,255,255,0.1)]",
                            isFirstRightPin &&
                              "shadow-[-1px_0_0_0_rgba(0,0,0,0.08)] dark:shadow-[-1px_0_0_0_rgba(255,255,255,0.1)]",
                            isSelected && "bg-muted/40",
                            canEdit && "cursor-text",
                            cellEditing && "bg-muted/30",
                            enableKeyboardNavigation &&
                              !isGroup &&
                              "outline-none focus-visible:ring-2 focus-visible:ring-ring/40 data-[focused=true]:ring-2 data-[focused=true]:ring-ring/50",
                            column.className,
                            classNames?.cell,
                          )}
                          style={{
                            ...sizeStyle,
                            ...(pinnedLeft != null
                              ? { left: pinnedLeft }
                              : null),
                            ...(pinnedRight != null
                              ? { right: pinnedRight }
                              : null),
                            ...styles?.cell,
                          }}
                          {...keyboardProps}
                          onDoubleClick={(event) => {
                            if (!canEdit) return;
                            event.stopPropagation();
                            const params = {
                              id,
                              field: column.key,
                              row,
                              value: rawValue,
                            };
                            if (editMode === "row") {
                              editing.startRowEdit(params);
                            } else {
                              editing.startCellEdit(params);
                            }
                          }}
                        >
                          {cellEditing ? (
                            <EditableCell
                              value={editValue}
                              editType={column.editType}
                              editOptions={column.editOptions}
                              radiusClass={radiusClass}
                              aria-label={locale.editFieldAria(column.header)}
                              onChange={(next) =>
                                editing.setDraftValue(column.key, next)
                              }
                              onCommit={(reason) => {
                                if (editMode === "row") return;
                                void editing.commitCellEdit(reason);
                              }}
                              onCancel={() => editing.cancelEdit("escape")}
                              renderEditCell={
                                column.renderEditCell
                                  ? (helpers) =>
                                      column.renderEditCell!({
                                        ...helpers,
                                        row,
                                        field: column.key,
                                      })
                                  : undefined
                              }
                            />
                          ) : showTreeChrome ? (
                            <div
                              className="flex min-w-0 items-center gap-0.5"
                              style={{
                                paddingLeft: `${(tree?.depth ?? 0) * 1.05}rem`,
                              }}
                            >
                              {isGroup ? (
                                <DetailExpandButton
                                  expanded={expandedTreeIdSet.has(id)}
                                  onToggle={() => toggleTreeExpanded(id)}
                                  variant="group"
                                  className="size-6"
                                />
                              ) : (
                                <span className="inline-block size-6 shrink-0" />
                              )}
                              <CellContent
                                wrap={column.wrap}
                                truncate={truncate}
                                title={
                                  isGroup
                                    ? tree?.label
                                    : truncate && !column.cell
                                      ? textValue
                                      : undefined
                                }
                              >
                                {isGroup ? tree?.label : content}
                              </CellContent>
                            </div>
                          ) : (
                            <CellContent
                              wrap={column.wrap}
                              truncate={truncate}
                              title={
                                truncate && !column.cell
                                  ? textValue
                                  : undefined
                              }
                            >
                              {content}
                            </CellContent>
                          )}
                        </TableCell>
                      );
                    })}

                    {showActions ? (
                      <TableCell
                        className={cn(
                          "bg-card",
                          densityCell,
                          cellBorderClass,
                          actionsSticky &&
                            "sticky right-0 z-20 shadow-[-1px_0_0_0_rgba(0,0,0,0.06)] dark:shadow-[-1px_0_0_0_rgba(255,255,255,0.08)]",
                          isSelected && "bg-muted/40",
                          classNames?.cell,
                        )}
                        style={{
                          width: Math.max(
                            actionsColumnWidth,
                            showRowEditControls && editing.isEditingRow(id)
                              ? 88
                              : actionsColumnWidth,
                          ),
                          minWidth: Math.max(
                            actionsColumnWidth,
                            showRowEditControls && editing.isEditingRow(id)
                              ? 88
                              : actionsColumnWidth,
                          ),
                        }}
                      >
                        {!isGroup ? (
                        <div className="flex items-center justify-end gap-0.5">
                          {showRowEditControls && editing.isEditingRow(id) ? (
                            <>
                              <Button
                                type="button"
                                size="icon-xs"
                                variant="ghost"
                                aria-label={locale.saveRowAria}
                                className={cn(
                                  "text-emerald-600 hover:bg-emerald-500/10 hover:text-emerald-700",
                                  radiusClass,
                                )}
                                onClick={(event) => {
                                  event.stopPropagation();
                                  void editing.commitRowEdit();
                                }}
                              >
                                <CheckIcon className="size-3.5" />
                              </Button>
                              <Button
                                type="button"
                                size="icon-xs"
                                variant="ghost"
                                aria-label={locale.cancelEditAria}
                                className={cn(
                                  "text-muted-foreground hover:bg-destructive/10 hover:text-destructive",
                                  radiusClass,
                                )}
                                onClick={(event) => {
                                  event.stopPropagation();
                                  editing.cancelEdit("rowCancel");
                                }}
                              >
                                <XIcon className="size-3.5" />
                              </Button>
                            </>
                          ) : null}

                          {actions ? (
                            <RowActions
                              row={row}
                              actions={resolveRowActions(actions, row, {
                                permissions: actionsOptions?.permissions,
                                canAccess: actionsOptions?.canAccess,
                              })}
                              display={resolvedActionsDisplay}
                              placement={popoverPlacement}
                              offsetDistance={popoverOffset}
                              radiusClass={radiusClass}
                              menuAriaLabel={
                                actionsOptions?.menuAriaLabel ??
                                locale.rowActionsAria(id)
                              }
                            />
                          ) : renderRowActions ? (
                            <RowActions
                              row={row}
                              actions={[]}
                              display="menu"
                              placement={popoverPlacement}
                              offsetDistance={popoverOffset}
                              radiusClass={radiusClass}
                              menuAriaLabel={locale.rowActionsAria(id)}
                            >
                              {renderRowActions(row)}
                            </RowActions>
                          ) : null}
                        </div>
                        ) : null}
                      </TableCell>
                    ) : null}
                  </TableRow>
                  {detailOpen && canExpandDetail ? (
                    <TableRow
                      data-slot="data-table-detail-panel"
                      className="hover:bg-transparent"
                    >
                      <TableCell
                        colSpan={colSpan}
                        className={cn(
                          "bg-muted/20",
                          densityCell,
                          classNames?.cell,
                          classNames?.detailPanel,
                        )}
                        style={{ ...styles?.cell, ...styles?.detailPanel }}
                        aria-label={locale.detailPanelAria}
                      >
                        {detailContent}
                      </TableCell>
                    </TableRow>
                  ) : null}
                  </React.Fragment>
                );
              })}

                {virtualization.enabled && virtualization.paddingBottom > 0 ? (
                  <tr aria-hidden="true">
                    <td
                      colSpan={colSpan}
                      style={{
                        height: virtualization.paddingBottom,
                        padding: 0,
                        border: 0,
                      }}
                    />
                  </tr>
                ) : null}
              </>
            )}
          </TableBody>
        </Table>
      </div>

      {showPagination ? (
        <TablePagination
          page={page}
          pageCount={pageCount}
          pageSize={pageSize}
          totalItems={totalItems}
          onPageChange={handlePageChange}
          onPageSizeChange={handlePageSizeChange}
          pageSizeOptions={resolvedPageSizeOptions}
          options={paginationOptions}
          className={classNames?.pagination}
          style={styles?.pagination}
          radiusClass={radiusClass}
        />
      ) : null}
    </div>
    </DataTableLocaleProvider>
  );
}

"use client";

import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "./components/ui/select";
import { cn } from "./lib/utils";
import { useDataTableLocale } from "./locale-text";
import { toolbarSelectTriggerClass } from "./toolbar-control";
import { DENSITY_OPTIONS, type DataTableDensity } from "./types";

export type DensityControlProps = {
  value: DataTableDensity;
  onChange: (value: DataTableDensity) => void;
  options?: typeof DENSITY_OPTIONS;
  className?: string;
  radiusClass?: string;
  /** Popper offset from the trigger (px). */
  sideOffset?: number;
};

export function DensityControl({
  value,
  onChange,
  options,
  className,
  radiusClass = "rounded-xs",
  sideOffset = 8,
}: DensityControlProps) {
  const locale = useDataTableLocale();
  const resolvedOptions =
    options ??
    DENSITY_OPTIONS.map((option) => ({
      ...option,
      label:
        option.value === "compact"
          ? locale.densityCompact
          : option.value === "comfortable"
            ? locale.densityComfortable
            : locale.densitySpacious,
    }));

  return (
    <Select
      value={value}
      onValueChange={(next) => onChange(next as DataTableDensity)}
    >
      <SelectTrigger
        size="sm"
        aria-label={locale.densityAriaLabel}
        data-slot="data-table-density-control"
        className={cn(
          toolbarSelectTriggerClass,
          "min-w-[6.5rem] data-[size=sm]:h-7",
          radiusClass,
          className,
        )}
      >
        <SelectValue placeholder={locale.densityLabel} />
      </SelectTrigger>
      <SelectContent
        position="popper"
        sideOffset={sideOffset}
        align="end"
        className={cn("min-w-[8.5rem] text-xs", radiusClass)}
      >
        {resolvedOptions.map((option) => (
          <SelectItem
            key={option.value}
            value={option.value}
            className="text-xs"
          >
            {option.label}
          </SelectItem>
        ))}
      </SelectContent>
    </Select>
  );
}

"use client";

import { ChevronDownIcon, ChevronRightIcon } from "lucide-react";

import { Button } from "./components/ui/button";
import { cn } from "./lib/utils";
import { useDataTableLocale } from "./locale-text";

export const DETAIL_EXPAND_COLUMN_WIDTH = 36;

export type DetailExpandButtonProps = {
  expanded: boolean;
  onToggle: () => void;
  disabled?: boolean;
  className?: string;
  /** Use group aria labels instead of row detail labels. */
  variant?: "detail" | "group";
};

export function DetailExpandButton({
  expanded,
  onToggle,
  disabled = false,
  className,
  variant = "detail",
}: DetailExpandButtonProps) {
  const locale = useDataTableLocale();
  const label =
    variant === "group"
      ? expanded
        ? locale.collapseGroupAria
        : locale.expandGroupAria
      : expanded
        ? locale.collapseRowAria
        : locale.expandRowAria;

  return (
    <Button
      type="button"
      variant="ghost"
      size="icon-xs"
      disabled={disabled}
      aria-expanded={expanded}
      aria-label={label}
      data-slot="data-table-expand-button"
      className={cn("size-7 shrink-0 text-muted-foreground", className)}
      onClick={(event) => {
        event.stopPropagation();
        onToggle();
      }}
    >
      {expanded ? (
        <ChevronDownIcon className="size-3.5" />
      ) : (
        <ChevronRightIcon className="size-3.5" />
      )}
    </Button>
  );
}

"use client";

import * as React from "react";

import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "./components/ui/select";
import { cn } from "./lib/utils";
import type { DataTableEditType } from "./use-table-editing";

export type EditableCellProps = {
  value: unknown;
  editType?: DataTableEditType;
  editOptions?: string[];
  radiusClass?: string;
  autoFocus?: boolean;
  "aria-label"?: string;
  onChange: (value: unknown) => void;
  onCommit: (reason: "enter" | "blur" | "tab") => void;
  onCancel: () => void;
  renderEditCell?: (helpers: {
    value: unknown;
    setValue: (value: unknown) => void;
    commit: (reason?: "enter" | "blur" | "tab") => void;
    cancel: () => void;
  }) => React.ReactNode;
};

const inputClass =
  "h-8 w-full min-w-0 border border-input bg-background px-2 text-xs outline-none focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50";

export function EditableCell({
  value,
  editType = "text",
  editOptions = [],
  radiusClass = "rounded-xs",
  autoFocus = true,
  "aria-label": ariaLabel,
  onChange,
  onCommit,
  onCancel,
  renderEditCell,
}: EditableCellProps) {
  const stringValue = value == null ? "" : String(value);

  if (renderEditCell) {
    return (
      <div
        className="min-w-0"
        onClick={(event) => event.stopPropagation()}
        onDoubleClick={(event) => event.stopPropagation()}
      >
        {renderEditCell({
          value,
          setValue: onChange,
          commit: (reason = "enter") => onCommit(reason),
          cancel: onCancel,
        })}
      </div>
    );
  }

  const stop = {
    onClick: (event: React.MouseEvent) => event.stopPropagation(),
    onDoubleClick: (event: React.MouseEvent) => event.stopPropagation(),
  };

  const onKeyDown = (event: React.KeyboardEvent) => {
    if (event.key === "Escape") {
      event.preventDefault();
      event.stopPropagation();
      onCancel();
      return;
    }
    if (event.key === "Enter" && editType !== "textarea") {
      event.preventDefault();
      event.stopPropagation();
      onCommit("enter");
      return;
    }
    if (event.key === "Tab") {
      event.stopPropagation();
      onCommit("tab");
    }
  };

  if (editType === "boolean") {
    const checked = value === true || value === "true";
    return (
      <button
        type="button"
        role="switch"
        aria-checked={checked}
        aria-label={ariaLabel}
        autoFocus={autoFocus}
        className={cn(
          "flex h-8 w-full items-center justify-between border border-input bg-background px-2 text-xs",
          radiusClass,
        )}
        {...stop}
        onKeyDown={onKeyDown}
        onBlur={() => onCommit("blur")}
        onClick={(event) => {
          event.stopPropagation();
          onChange(!checked);
        }}
      >
        <span className="text-muted-foreground">Boolean</span>
        <span className="font-medium">{checked ? "true" : "false"}</span>
      </button>
    );
  }

  if (editType === "select") {
    return (
      <div {...stop} onKeyDown={onKeyDown}>
        <Select
          value={stringValue || undefined}
          onValueChange={(next) => {
            onChange(next);
            // Commit after select so the menu can close cleanly.
            queueMicrotask(() => onCommit("enter"));
          }}
        >
          <SelectTrigger
            size="sm"
            aria-label={ariaLabel}
            className={cn(
              "h-8 w-full border-input px-2 text-xs shadow-none data-[size=sm]:h-8",
              radiusClass,
            )}
          >
            <SelectValue placeholder="Select…" />
          </SelectTrigger>
          <SelectContent
            position="popper"
            sideOffset={8}
            align="start"
            className={cn("z-[80] text-xs", radiusClass)}
          >
            {editOptions.map((option) => (
              <SelectItem key={option} value={option} className="text-xs">
                {option}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>
    );
  }

  if (editType === "textarea") {
    return (
      <textarea
        aria-label={ariaLabel}
        autoFocus={autoFocus}
        className={cn(
          "min-h-16 w-full resize-y border border-input bg-background px-2 py-1.5 text-xs outline-none focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50",
          radiusClass,
        )}
        value={stringValue}
        {...stop}
        onChange={(event) => onChange(event.target.value)}
        onKeyDown={(event) => {
          if (event.key === "Escape") {
            event.preventDefault();
            onCancel();
          }
          if (event.key === "Enter" && (event.metaKey || event.ctrlKey)) {
            event.preventDefault();
            onCommit("enter");
          }
        }}
        onBlur={() => onCommit("blur")}
      />
    );
  }

  return (
    <input
      type={editType === "number" ? "number" : "text"}
      aria-label={ariaLabel}
      autoFocus={autoFocus}
      className={cn(inputClass, radiusClass)}
      value={stringValue}
      {...stop}
      onChange={(event) => {
        const next = event.target.value;
        onChange(editType === "number" ? (next === "" ? "" : Number(next)) : next);
      }}
      onKeyDown={onKeyDown}
      onBlur={() => onCommit("blur")}
    />
  );
}

"use client";

import * as React from "react";
import {
  CheckIcon,
  ClipboardCopyIcon,
  DownloadIcon,
  FileSpreadsheetIcon,
} from "lucide-react";
import {
  FloatingPortal,
  autoUpdate,
  flip,
  offset,
  shift,
  useClick,
  useDismiss,
  useFloating,
  useInteractions,
  useRole,
} from "@floating-ui/react";

import { cn } from "./lib/utils";
import { useDataTableLocale } from "./locale-text";
import { toolbarSelectTriggerClass } from "./toolbar-control";
import {
  buildCsv,
  copyTextToClipboard,
  downloadTextFile,
} from "./export-utils";

export type ExportMenuProps = {
  getCsv: () => { headers: string[]; matrix: unknown[][] };
  filename?: string;
  radiusClass?: string;
  className?: string;
  popoverOffset?: number;
  onExported?: (format: "csv" | "clipboard") => void;
};

export function ExportMenu({
  getCsv,
  filename = "table-export.csv",
  radiusClass = "rounded-xs",
  className,
  popoverOffset = 8,
  onExported,
}: ExportMenuProps) {
  const locale = useDataTableLocale();
  const [open, setOpen] = React.useState(false);
  const [copied, setCopied] = React.useState(false);

  const { refs, floatingStyles, context } = useFloating({
    open,
    onOpenChange: setOpen,
    placement: "bottom-end",
    strategy: "fixed",
    whileElementsMounted: autoUpdate,
    middleware: [
      offset(popoverOffset),
      flip({ padding: 8 }),
      shift({ padding: 8 }),
    ],
  });

  const click = useClick(context);
  const dismiss = useDismiss(context);
  const role = useRole(context, { role: "menu" });
  const { getReferenceProps, getFloatingProps } = useInteractions([
    click,
    dismiss,
    role,
  ]);

  const exportCsv = () => {
    const { headers, matrix } = getCsv();
    const csv = buildCsv(headers, matrix);
    downloadTextFile(csv, filename);
    onExported?.("csv");
    setOpen(false);
  };

  const copyCsv = async () => {
    const { headers, matrix } = getCsv();
    const csv = buildCsv(headers, matrix);
    const ok = await copyTextToClipboard(csv);
    if (ok) {
      setCopied(true);
      onExported?.("clipboard");
      window.setTimeout(() => setCopied(false), 1500);
    }
    setOpen(false);
  };

  const itemClass = cn(
    "flex w-full items-center gap-2 px-2.5 py-2 text-left text-xs outline-none hover:bg-muted",
    radiusClass,
  );

  return (
    <>
      <button
        type="button"
        ref={refs.setReference}
        aria-expanded={open}
        data-slot="data-table-export-trigger"
        className={cn(
          toolbarSelectTriggerClass,
          "min-w-[6.25rem]",
          radiusClass,
          className,
        )}
        {...getReferenceProps()}
      >
        <span className="inline-flex min-w-0 items-center gap-1.5">
          <DownloadIcon className="size-3 opacity-70" />
          <span className="truncate">{locale.exportLabel}</span>
        </span>
      </button>

      {open ? (
        <FloatingPortal>
          <div
            ref={refs.setFloating}
            style={floatingStyles}
            data-slot="data-table-export-menu"
            className={cn(
              "z-50 min-w-44 border border-input bg-popover p-1 text-popover-foreground shadow-md",
              radiusClass,
            )}
            {...getFloatingProps()}
          >
            <button type="button" role="menuitem" className={itemClass} onClick={exportCsv}>
              <FileSpreadsheetIcon className="size-3.5" />
              {locale.exportDownloadCsv}
            </button>
            <button type="button" role="menuitem" className={itemClass} onClick={() => void copyCsv()}>
              {copied ? (
                <CheckIcon className="size-3.5 text-emerald-600" />
              ) : (
                <ClipboardCopyIcon className="size-3.5" />
              )}
              {copied ? locale.exportCopied : locale.exportCopyCsv}
            </button>
          </div>
        </FloatingPortal>
      ) : null}
    </>
  );
}

/** Escape a CSV field (RFC-style quotes). */
export function escapeCsvValue(value: unknown): string {
  const text = value == null ? "" : String(value);
  if (/[",\n\r]/.test(text)) {
    return `"${text.replace(/"/g, '""')}"`;
  }
  return text;
}

export type BuildCsvOptions = {
  /** Include header row. Defaults to `true`. */
  includeHeaders?: boolean;
  /** Line ending. Defaults to `\\r\\n`. */
  lineEnding?: "\n" | "\r\n";
};

export function buildCsv(
  headers: string[],
  rows: unknown[][],
  options: BuildCsvOptions = {},
): string {
  const includeHeaders = options.includeHeaders ?? true;
  const lineEnding = options.lineEnding ?? "\r\n";
  const lines: string[] = [];

  if (includeHeaders) {
    lines.push(headers.map(escapeCsvValue).join(","));
  }

  for (const row of rows) {
    lines.push(row.map(escapeCsvValue).join(","));
  }

  return lines.join(lineEnding);
}

export function downloadTextFile(
  content: string,
  filename: string,
  mimeType = "text/csv;charset=utf-8",
) {
  if (typeof document === "undefined") return;
  const blob = new Blob([content], { type: mimeType });
  const url = URL.createObjectURL(blob);
  const anchor = document.createElement("a");
  anchor.href = url;
  anchor.download = filename;
  anchor.rel = "noopener";
  document.body.appendChild(anchor);
  anchor.click();
  anchor.remove();
  URL.revokeObjectURL(url);
}

export async function copyTextToClipboard(text: string): Promise<boolean> {
  if (typeof navigator === "undefined") return false;
  try {
    if (navigator.clipboard?.writeText) {
      await navigator.clipboard.writeText(text);
      return true;
    }
  } catch {
    // fall through
  }

  try {
    const textarea = document.createElement("textarea");
    textarea.value = text;
    textarea.setAttribute("readonly", "");
    textarea.style.position = "fixed";
    textarea.style.left = "-9999px";
    document.body.appendChild(textarea);
    textarea.select();
    const ok = document.execCommand("copy");
    textarea.remove();
    return ok;
  } catch {
    return false;
  }
}

export type ExportTableDataOptions<T> = {
  columns: Array<{ key: string; header: string }>;
  rows: T[];
  getValue: (row: T, key: string) => unknown;
  filename?: string;
  includeHeaders?: boolean;
};

export function rowsToCsvMatrix<T>({
  columns,
  rows,
  getValue,
}: Omit<ExportTableDataOptions<T>, "filename" | "includeHeaders">): {
  headers: string[];
  matrix: unknown[][];
} {
  const headers = columns.map((column) => column.header);
  const matrix = rows.map((row) =>
    columns.map((column) => getValue(row, column.key)),
  );
  return { headers, matrix };
}

"use client";

import * as React from "react";
import { XIcon } from "lucide-react";

import { Button } from "./components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "./components/ui/select";
import { cn } from "./lib/utils";
import { useDataTableLocale } from "./locale-text";
import type { DataTableColumn, DataTableFilters } from "./types";

export type FilterBarProps<T> = {
  columns: DataTableColumn<T>[];
  filters: DataTableFilters;
  onFiltersChange: (filters: DataTableFilters) => void;
  className?: string;
  radiusClass?: string;
  style?: React.CSSProperties;
};

export function FilterBar<T>({
  columns,
  filters,
  onFiltersChange,
  className,
  radiusClass = "",
  style,
}: FilterBarProps<T>) {
  const locale = useDataTableLocale();
  const filterableColumns = columns.filter((column) => column.filterable);

  if (filterableColumns.length === 0) {
    return null;
  }

  const activeCount = Object.values(filters).filter(
    (value) => value != null && String(value).trim() !== "",
  ).length;

  const setFilter = (key: string, value: string) => {
    const next = { ...filters };
    if (value.trim() === "" || value === "__all__") {
      delete next[key];
    } else {
      next[key] = value;
    }
    onFiltersChange(next);
  };

  const clearFilters = () => onFiltersChange({});

  return (
    <div
      data-slot="data-table-filter-bar"
      style={style}
      className={cn(
        "flex flex-wrap items-end gap-3 border-b border-black/[0.04] px-3 py-3 dark:border-white/[0.06]",
        className,
      )}
    >
      {filterableColumns.map((column) => {
        const filterType = column.filterType ?? "text";
        const value = filters[column.key] ?? "";

        return (
          <label
            key={column.key}
            className="flex min-w-40 flex-1 flex-col gap-1.5"
          >
            <span className="text-xs font-medium text-muted-foreground">
              {column.header}
            </span>
            {filterType === "select" ? (
              <Select
                value={value || "__all__"}
                onValueChange={(next) => setFilter(column.key, next)}
              >
                <SelectTrigger
                  size="sm"
                  className={cn("h-8 w-full shadow-none", radiusClass)}
                  aria-label={locale.filterBarAria(column.header)}
                >
                  <SelectValue placeholder={locale.filterBarAll} />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="__all__">{locale.filterBarAll}</SelectItem>
                  {(column.filterOptions ?? []).map((option) => (
                    <SelectItem key={option} value={option}>
                      {option}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            ) : (
              <input
                type="search"
                value={value}
                onChange={(event) => setFilter(column.key, event.target.value)}
                placeholder={locale.filterBarPlaceholder(column.header)}
                aria-label={locale.filterBarAria(column.header)}
                className={cn(
                  "h-8 w-full border border-input bg-transparent px-2.5 text-sm outline-none placeholder:text-muted-foreground focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50",
                  radiusClass,
                )}
              />
            )}
          </label>
        );
      })}

      {activeCount > 0 ? (
        <div className="flex items-center gap-2 pb-0.5">
          <span className="text-xs text-muted-foreground">
            {locale.filterBarActiveCount(activeCount)}
          </span>
          <Button
            type="button"
            variant="ghost"
            size="sm"
            onClick={clearFilters}
            className={cn("h-8 gap-1 px-2 text-muted-foreground", radiusClass)}
          >
            <XIcon className="size-3.5" />
            {locale.filterBarClear}
          </Button>
        </div>
      ) : null}
    </div>
  );
}

"use client";

import * as React from "react";
import { CheckIcon, ChevronsUpDownIcon, SearchIcon } from "lucide-react";
import {
  FloatingPortal,
  autoUpdate,
  flip,
  offset,
  shift,
  size,
  useClick,
  useDismiss,
  useFloating,
  useInteractions,
  useRole,
} from "@floating-ui/react";

import { cn } from "../lib/utils";
import { FILTER_TYPE_META, type FilterBuilderColumn } from "./types";

export type FilterColumnSelectProps = {
  columns: readonly FilterBuilderColumn[];
  value: string;
  onChange: (value: string) => void;
  radiusClass?: string;
};

export function FilterColumnSelect({
  columns,
  value,
  onChange,
  radiusClass = "rounded-xs",
}: FilterColumnSelectProps) {
  const [open, setOpen] = React.useState(false);
  const [query, setQuery] = React.useState("");

  const selected = React.useMemo(
    () => columns.find((column) => column.value === value),
    [columns, value],
  );
  const meta = selected ? FILTER_TYPE_META[selected.type] : null;

  const { refs, floatingStyles, context } = useFloating({
    open,
    onOpenChange: (next) => {
      setOpen(next);
      if (!next) setQuery("");
    },
    placement: "bottom-start",
    strategy: "fixed",
    whileElementsMounted: autoUpdate,
    middleware: [
      offset(6),
      flip({ padding: 8 }),
      shift({ padding: 8 }),
      size({
        apply({ rects, elements }) {
          Object.assign(elements.floating.style, {
            width: `${Math.max(rects.reference.width, 220)}px`,
          });
        },
      }),
    ],
  });

  const click = useClick(context);
  const dismiss = useDismiss(context);
  const role = useRole(context, { role: "listbox" });
  const { getReferenceProps, getFloatingProps } = useInteractions([
    click,
    dismiss,
    role,
  ]);

  const filtered = columns.filter((column) => {
    const haystack =
      `${column.label} ${column.value} ${column.type}`.toLowerCase();
    return haystack.includes(query.trim().toLowerCase());
  });

  const pick = (next: string) => {
    onChange(next);
    setOpen(false);
    setQuery("");
  };

  return (
    <>
      <button
        type="button"
        ref={refs.setReference}
        aria-expanded={open}
        data-slot="data-table-filter-column-trigger"
        className={cn(
          "inline-flex h-8 w-full items-center justify-between gap-1.5 border border-input bg-background px-2.5 text-xs shadow-none outline-none transition-colors hover:bg-muted/40 focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50",
          radiusClass,
        )}
        {...getReferenceProps({
          onClick: (event) => event.stopPropagation(),
          onPointerDown: (event) => event.stopPropagation(),
        })}
      >
        <span className="inline-flex min-w-0 items-center gap-2">
          {meta ? (
            <span
              className={cn("size-1.5 shrink-0 rounded-full", meta.dot)}
              aria-hidden="true"
            />
          ) : null}
          <span className="truncate font-medium">
            {selected?.label ?? "Select column"}
          </span>
        </span>
        <ChevronsUpDownIcon className="size-3.5 shrink-0 opacity-40" />
      </button>

      {open ? (
        <FloatingPortal>
          <div
            ref={refs.setFloating}
            style={floatingStyles}
            data-slot="data-table-filter-column-select"
            className={cn(
              "z-[80] overflow-hidden border border-input bg-popover text-popover-foreground shadow-lg",
              radiusClass,
            )}
            {...getFloatingProps({
              onClick: (event) => event.stopPropagation(),
              onPointerDown: (event) => event.stopPropagation(),
            })}
          >
            <div className="border-b border-black/[0.04] p-1.5 dark:border-white/[0.06]">
              <div className="relative">
                <SearchIcon className="pointer-events-none absolute top-1/2 left-2.5 size-3.5 -translate-y-1/2 text-muted-foreground" />
                <input
                  type="search"
                  value={query}
                  autoFocus
                  onChange={(event) => setQuery(event.target.value)}
                  onKeyDown={(event) => {
                    if (event.key === "Enter" && filtered[0]) {
                      event.preventDefault();
                      pick(filtered[0].value);
                    }
                  }}
                  placeholder="Search columns…"
                  className={cn(
                    "h-8 w-full border border-input bg-transparent py-1 pr-2 pl-8 text-xs outline-none placeholder:text-muted-foreground focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50",
                    radiusClass,
                  )}
                />
              </div>
            </div>
            <ul className="data-table-thin-scroll max-h-56 overflow-auto p-1">
              {filtered.length === 0 ? (
                <li className="px-2 py-4 text-center text-xs text-muted-foreground">
                  No column found
                </li>
              ) : (
                filtered.map((column) => {
                  const itemMeta = FILTER_TYPE_META[column.type];
                  const active = value === column.value;
                  return (
                    <li key={column.value}>
                      <button
                        type="button"
                        role="option"
                        aria-selected={active}
                        className={cn(
                          "flex w-full items-center gap-2 px-2 py-2 text-left text-xs transition-colors",
                          radiusClass,
                          active
                            ? "bg-muted text-foreground"
                            : "hover:bg-muted/70",
                        )}
                        onClick={(event) => {
                          event.preventDefault();
                          event.stopPropagation();
                          pick(column.value);
                        }}
                      >
                        <CheckIcon
                          className={cn(
                            "size-3.5 shrink-0",
                            active ? "opacity-100" : "opacity-0",
                          )}
                        />
                        <span
                          className={cn(
                            "size-1.5 shrink-0 rounded-full",
                            itemMeta.dot,
                          )}
                        />
                        <span className="min-w-0 flex-1 truncate font-medium">
                          {column.label}
                        </span>
                        <span
                          className={cn(
                            "px-1.5 py-0.5 text-[10px] font-medium",
                            radiusClass,
                            itemMeta.badge,
                          )}
                        >
                          {itemMeta.label}
                        </span>
                      </button>
                    </li>
                  );
                })
              )}
            </ul>
          </div>
        </FloatingPortal>
      ) : null}
    </>
  );
}

"use client";

import * as React from "react";
