export const DEFAULT_COLUMN_MIN_WIDTH = 80;
export const DEFAULT_COLUMN_WIDTH = 160;

/** Resolve layout styles from column size props + optional live resize width. */
export function getColumnSizeStyle(
  column: {
    width?: number;
    minWidth?: number;
    maxWidth?: number;
  },
  resizedWidth?: number,
): React.CSSProperties {
  const width = resizedWidth ?? column.width;
  const minWidth = column.minWidth ?? width;
  const maxWidth = column.maxWidth;

  const style: React.CSSProperties = {};
  if (width != null) style.width = width;
  if (minWidth != null) style.minWidth = minWidth;
  if (maxWidth != null) style.maxWidth = maxWidth;
  // Keep truncated cells constrained so ellipsis can appear in table layout.
  if (maxWidth == null && width != null) style.maxWidth = width;
  return style;
}

export function shouldTruncateColumn(column: {
  wrap?: boolean;
  truncate?: boolean;
}): boolean {
  if (column.wrap) return false;
  return column.truncate !== false;
}

export function isColumnVisible(
  visibility: DataTableColumnVisibility,
  key: string,
): boolean {
  return visibility[key] !== false;
}

export function getVisibleColumns<T>(
  columns: DataTableColumn<T>[],
  visibility: DataTableColumnVisibility,
): DataTableColumn<T>[] {
  return columns.filter((column) => isColumnVisible(visibility, column.key));
}

/** Apply optional columnOrder, then visibility. */
export function orderColumns<T>(
  columns: DataTableColumn<T>[],
  order: string[],
): DataTableColumn<T>[] {
  if (order.length === 0) return columns;
  const byKey = new Map(columns.map((column) => [column.key, column]));
  const ordered: DataTableColumn<T>[] = [];
  for (const key of order) {
    const column = byKey.get(key);
    if (column) {
      ordered.push(column);
      byKey.delete(key);
    }
  }
  for (const column of byKey.values()) ordered.push(column);
  return ordered;
}

export function resolvePinnedSide(
  key: string,
  pinnedColumns: DataTablePinnedColumns,
  columnPinned?: "left" | "right",
): "left" | "right" | false {
  if (pinnedColumns.left?.includes(key)) return "left";
  if (pinnedColumns.right?.includes(key)) return "right";
  if (columnPinned) return columnPinned;
  return false;
}

/**
 * Move left-pinned columns to the front and right-pinned to the end
 * (after checkbox/SN are accounted for separately in the table).
 */
export function applyPinOrder<T>(
  columns: DataTableColumn<T>[],
  pinnedColumns: DataTablePinnedColumns,
): DataTableColumn<T>[] {
  const left: DataTableColumn<T>[] = [];
  const center: DataTableColumn<T>[] = [];
  const right: DataTableColumn<T>[] = [];

  for (const column of columns) {
    const side = resolvePinnedSide(
      column.key,
      pinnedColumns,
      column.pinned ?? (column.sticky ? "left" : undefined),
    );
    if (side === "left") left.push(column);
    else if (side === "right") right.push(column);
    else center.push(column);
  }

  const sortByPinList = (
    group: DataTableColumn<T>[],
    list: string[] | undefined,
  ) => {
    if (!list?.length) return group;
    return [...group].sort((a, b) => {
      const ai = list.indexOf(a.key);
      const bi = list.indexOf(b.key);
      if (ai === -1 && bi === -1) return 0;
      if (ai === -1) return 1;
      if (bi === -1) return -1;
      return ai - bi;
    });
  };

  return [
    ...sortByPinList(left, pinnedColumns.left),
    ...center,
    ...sortByPinList(right, pinnedColumns.right),
  ];
}

export function resolveRowActions<T>(
  actions:
    | DataTableRowAction<T>[]
    | ((row: T) => DataTableRowAction<T>[])
    | undefined,
  row: T,
  options?: Pick<DataTableActionsOptions<T>, "permissions" | "canAccess">,
): DataTableRowAction<T>[] {
  if (!actions) return [];
  const list = typeof actions === "function" ? actions(row) : actions;
  return list.filter((action) => isRowActionVisible(action, row, options));
}

export function isRowActionVisible<T>(
  action: DataTableRowAction<T>,
  row: T,
  options?: Pick<DataTableActionsOptions<T>, "permissions" | "canAccess">,
): boolean {
  if (action.show !== undefined) {
    const shown =
      typeof action.show === "function" ? action.show(row) : action.show;
    if (!shown) return false;
  }

  if (action.hidden !== undefined) {
    const hidden =
      typeof action.hidden === "function"
        ? action.hidden(row)
        : Boolean(action.hidden);
    if (hidden) return false;
  }

  if (action.permission !== undefined) {
    if (typeof action.permission === "function") {
      if (!action.permission(row)) return false;
    } else if (!hasActionPermission(action.permission, row, options)) {
      return false;
    }
  }

  return true;
}

export function hasActionPermission<T>(
  permission: string,
  row: T,
  options?: Pick<DataTableActionsOptions<T>, "permissions" | "canAccess">,
): boolean {
  if (options?.canAccess) return options.canAccess(permission, row);

  const perms = options?.permissions;
  if (perms == null) return true;
  if (Array.isArray(perms)) return perms.includes(permission);
  return perms[permission] === true;
}

export function splitRowActionsByDisplay<T>(
  actions: DataTableRowAction<T>[],
  display: DataTableActionsDisplay = "menu",
): { iconActions: DataTableRowAction<T>[]; menuActions: DataTableRowAction<T>[] } {
  if (display === "icons") {
    return { iconActions: actions, menuActions: [] };
  }
  return { iconActions: [], menuActions: actions };
}

export function isRowActionDisabled<T>(
  action: DataTableRowAction<T>,
  row: T,
): boolean {
  return typeof action.disabled === "function"
    ? action.disabled(row)
    : Boolean(action.disabled);
}

export function normalizeSort(
  value: DataTableSort | DataTableSort[] | null | undefined,
): DataTableSort[] {
  if (!value) return [];
  return Array.isArray(value) ? value : [value];
}

/** Cycle a column through asc → desc → removed. Preserves other sort keys. */
export function cycleMultiSort(
  current: DataTableSort[],
  key: string,
  options?: { replace?: boolean },
): DataTableSort[] {
  const replace = options?.replace ?? false;
  const existing = current.find((item) => item.key === key);

  if (replace) {
    if (!existing) return [{ key, direction: "asc" }];
    if (existing.direction === "asc") return [{ key, direction: "desc" }];
    return [];
  }

  if (!existing) return [...current, { key, direction: "asc" }];
  if (existing.direction === "asc") {
    return current.map((item) =>
      item.key === key ? { key, direction: "desc" } : item,
    );
  }
  return current.filter((item) => item.key !== key);
}

"use client";

import * as React from "react";

import {
  DEFAULT_COLUMN_MIN_WIDTH,
  DEFAULT_COLUMN_WIDTH,
  type DataTableColumn,
  type DataTableColumnWidths,
} from "./types";

export type UseColumnResizeOptions<T> = {
  columns: DataTableColumn<T>[];
  enabled?: boolean;
  columnWidths?: DataTableColumnWidths;
  defaultColumnWidths?: DataTableColumnWidths;
  onColumnWidthsChange?: (widths: DataTableColumnWidths) => void;
};

export type UseColumnResizeReturn = {
  widths: DataTableColumnWidths;
  getWidth: (
    key: string,
    column?: { width?: number; minWidth?: number },
  ) => number;
  setWidth: (
    key: string,
    width: number,
    options?: { minWidth?: number; maxWidth?: number },
  ) => void;
  beginResize: (
    key: string,
    event: React.MouseEvent | React.TouchEvent,
    options?: { minWidth?: number; maxWidth?: number },
  ) => void;
  isResizing: boolean;
};

function initialWidths<T>(
  columns: DataTableColumn<T>[],
  seed: DataTableColumnWidths = {},
): DataTableColumnWidths {
  const next: DataTableColumnWidths = { ...seed };
  for (const column of columns) {
    if (next[column.key] == null) {
      next[column.key] = column.width ?? DEFAULT_COLUMN_WIDTH;
    }
  }
  return next;
}

export function useColumnResize<T>({
  columns,
  enabled = false,
  columnWidths: controlledWidths,
  defaultColumnWidths = {},
  onColumnWidthsChange,
}: UseColumnResizeOptions<T>): UseColumnResizeReturn {
  const [uncontrolledWidths, setUncontrolledWidths] =
    React.useState<DataTableColumnWidths>(() =>
      initialWidths(columns, defaultColumnWidths),
    );
  const [isResizing, setIsResizing] = React.useState(false);

  const isControlled = controlledWidths !== undefined;
  const widths = isControlled
    ? initialWidths(columns, controlledWidths)
    : uncontrolledWidths;

  const widthsRef = React.useRef(widths);
  widthsRef.current = widths;

  React.useEffect(() => {
    if (isControlled) return;
    setUncontrolledWidths((prev) => initialWidths(columns, prev));
  }, [columns, isControlled]);

  const commitWidths = React.useCallback(
    (next: DataTableColumnWidths) => {
      widthsRef.current = next;
      if (!isControlled) setUncontrolledWidths(next);
      onColumnWidthsChange?.(next);
    },
    [isControlled, onColumnWidthsChange],
  );

  const getWidth = React.useCallback(
    (key: string, column?: { width?: number; minWidth?: number }) => {
      return (
        widthsRef.current[key] ??
        column?.width ??
        Math.max(
          column?.minWidth ?? DEFAULT_COLUMN_MIN_WIDTH,
          DEFAULT_COLUMN_WIDTH,
        )
      );
    },
    [],
  );

  const setWidth = React.useCallback(
    (
      key: string,
      width: number,
      options?: { minWidth?: number; maxWidth?: number },
    ) => {
      const minWidth = options?.minWidth ?? DEFAULT_COLUMN_MIN_WIDTH;
      const maxWidth = options?.maxWidth ?? Number.POSITIVE_INFINITY;
      const nextWidth = Math.min(
        maxWidth,
        Math.max(minWidth, Math.round(width)),
      );
      commitWidths({ ...widthsRef.current, [key]: nextWidth });
    },
    [commitWidths],
  );

  const beginResize = React.useCallback(
    (
      key: string,
      event: React.MouseEvent | React.TouchEvent,
      options?: { minWidth?: number; maxWidth?: number },
    ) => {
      if (!enabled) return;

      event.preventDefault();
      event.stopPropagation();

      const startX =
        "touches" in event ? event.touches[0]?.clientX ?? 0 : event.clientX;
      const startWidth = getWidth(key);
      const minWidth = options?.minWidth ?? DEFAULT_COLUMN_MIN_WIDTH;
      const maxWidth = options?.maxWidth ?? Number.POSITIVE_INFINITY;

      setIsResizing(true);

      const onMove = (clientX: number) => {
        setWidth(key, startWidth + (clientX - startX), { minWidth, maxWidth });
      };

      const onMouseMove = (moveEvent: MouseEvent) => onMove(moveEvent.clientX);
      const onTouchMove = (moveEvent: TouchEvent) => {
        const x = moveEvent.touches[0]?.clientX;
        if (x != null) onMove(x);
      };

      const onEnd = () => {
        setIsResizing(false);
        window.removeEventListener("mousemove", onMouseMove);
        window.removeEventListener("mouseup", onEnd);
        window.removeEventListener("touchmove", onTouchMove);
        window.removeEventListener("touchend", onEnd);
      };

      window.addEventListener("mousemove", onMouseMove);
      window.addEventListener("mouseup", onEnd);
      window.addEventListener("touchmove", onTouchMove, { passive: true });
      window.addEventListener("touchend", onEnd);
    },
    [enabled, getWidth, setWidth],
  );

  return { widths, getWidth, setWidth, beginResize, isResizing };
}

"use client";

import * as React from "react";

export type DataTableEditMode = "cell" | "row";

export type DataTableEditType =
  | "text"
  | "number"
  | "select"
  | "boolean"
  | "textarea";

export type DataTableEditingCell = {
  id: string;
  field: string;
};

export type DataTableCellParams<T> = {
  id: string;
  field: string;
  row: T;
  value: unknown;
};

export type DataTableEditStopParams<T> = DataTableCellParams<T> & {
  reason: "enter" | "blur" | "escape" | "tab" | "rowSave" | "rowCancel";
};

export type UseTableEditingOptions<T> = {
  editMode?: DataTableEditMode;
  getRowId: (row: T, index: number) => string;
  processRowUpdate?: (newRow: T, oldRow: T) => T | Promise<T>;
  onProcessRowUpdateError?: (error: unknown) => void;
  onCellEditStart?: (params: DataTableCellParams<T>) => void;
  onCellEditStop?: (params: DataTableEditStopParams<T>) => void;
  isCellEditable?: (params: DataTableCellParams<T>) => boolean;
};

export type UseTableEditingReturn<T> = {
  editMode: DataTableEditMode;
  editingCell: DataTableEditingCell | null;
  editingRowId: string | null;
  draft: Record<string, unknown>;
  isEditingCell: (id: string, field: string) => boolean;
  isEditingRow: (id: string) => boolean;
  getDisplayRow: (row: T, id: string) => T;
  startCellEdit: (params: DataTableCellParams<T>) => void;
  startRowEdit: (params: DataTableCellParams<T>) => void;
  setDraftValue: (field: string, value: unknown) => void;
  cancelEdit: (reason?: DataTableEditStopParams<T>["reason"]) => void;
  commitCellEdit: (
    reason?: DataTableEditStopParams<T>["reason"],
  ) => Promise<boolean>;
  commitRowEdit: () => Promise<boolean>;
  /** Merged rows after successful updates (id → row). */
  rowOverrides: Record<string, T>;
};

function setFieldValue<T>(row: T, field: string, value: unknown): T {
  if (row === null || typeof row !== "object") return row;
  return { ...(row as object), [field]: value } as T;
}

export function useTableEditing<T>({
  editMode = "cell",
  getRowId,
  processRowUpdate,
  onProcessRowUpdateError,
  onCellEditStart,
  onCellEditStop,
  isCellEditable,
}: UseTableEditingOptions<T>): UseTableEditingReturn<T> {
  const [editingCell, setEditingCell] =
    React.useState<DataTableEditingCell | null>(null);
  const [editingRowId, setEditingRowId] = React.useState<string | null>(null);
  const [draft, setDraft] = React.useState<Record<string, unknown>>({});
  const [rowOverrides, setRowOverrides] = React.useState<Record<string, T>>(
    {},
  );
  const baselineRef = React.useRef<T | null>(null);

  const getDisplayRow = React.useCallback(
    (row: T, id: string) => rowOverrides[id] ?? row,
    [rowOverrides],
  );

  const isEditingCell = React.useCallback(
    (id: string, field: string) =>
      editMode === "cell"
        ? editingCell?.id === id && editingCell.field === field
        : editingRowId === id,
    [editMode, editingCell, editingRowId],
  );

  const isEditingRow = React.useCallback(
    (id: string) => editingRowId === id,
    [editingRowId],
  );

  const startCellEdit = React.useCallback(
    (params: DataTableCellParams<T>) => {
      if (isCellEditable && !isCellEditable(params)) return;
      baselineRef.current = params.row;
      setEditingRowId(null);
      setEditingCell({ id: params.id, field: params.field });
      setDraft({ [params.field]: params.value ?? "" });
      onCellEditStart?.(params);
    },
    [isCellEditable, onCellEditStart],
  );

  const startRowEdit = React.useCallback(
    (params: DataTableCellParams<T>) => {
      if (isCellEditable && !isCellEditable(params)) return;
      baselineRef.current = params.row;
      setEditingCell(null);
      setEditingRowId(params.id);
      setDraft({});
      onCellEditStart?.(params);
    },
    [isCellEditable, onCellEditStart],
  );

  const setDraftValue = React.useCallback((field: string, value: unknown) => {
    setDraft((prev) => ({ ...prev, [field]: value }));
  }, []);

  const cancelEdit = React.useCallback(
    (reason: DataTableEditStopParams<T>["reason"] = "escape") => {
      const baseline = baselineRef.current;
      if (baseline && (editingCell || editingRowId)) {
        const id = editingCell?.id ?? editingRowId!;
        const field = editingCell?.field ?? "";
        onCellEditStop?.({
          id,
          field,
          row: baseline,
          value: field ? draft[field] : undefined,
          reason,
        });
      }
      setEditingCell(null);
      setEditingRowId(null);
      setDraft({});
      baselineRef.current = null;
    },
    [draft, editingCell, editingRowId, onCellEditStop],
  );

  const applyUpdate = React.useCallback(
    async (oldRow: T, nextRow: T, stop: DataTableEditStopParams<T>) => {
      try {
        const resolved = processRowUpdate
          ? await processRowUpdate(nextRow, oldRow)
          : nextRow;
        const id = stop.id;
        setRowOverrides((prev) => ({ ...prev, [id]: resolved }));
        onCellEditStop?.(stop);
        setEditingCell(null);
        setEditingRowId(null);
        setDraft({});
        baselineRef.current = null;
        return true;
      } catch (error) {
        onProcessRowUpdateError?.(error);
        return false;
      }
    },
    [onCellEditStop, onProcessRowUpdateError, processRowUpdate],
  );

  const commitCellEdit = React.useCallback(
    async (reason: DataTableEditStopParams<T>["reason"] = "enter") => {
      if (!editingCell || !baselineRef.current) return false;
      if (reason === "escape") {
        cancelEdit("escape");
        return false;
      }
      const oldRow = baselineRef.current;
      const value = draft[editingCell.field];
      const nextRow = setFieldValue(oldRow, editingCell.field, value);
      return applyUpdate(oldRow, nextRow, {
        id: editingCell.id,
        field: editingCell.field,
        row: nextRow,
        value,
        reason,
      });
    },
    [applyUpdate, cancelEdit, draft, editingCell],
  );

  const commitRowEdit = React.useCallback(async () => {
    if (!editingRowId || !baselineRef.current) return false;
    const oldRow = baselineRef.current;
    let nextRow = oldRow;
    for (const [field, value] of Object.entries(draft)) {
      nextRow = setFieldValue(nextRow, field, value);
    }
    return applyUpdate(oldRow, nextRow, {
      id: editingRowId,
      field: "",
      row: nextRow,
      value: undefined,
      reason: "rowSave",
    });
  }, [applyUpdate, draft, editingRowId]);

  // Silence unused getRowId for now — kept for API symmetry / future focus nav.
  void getRowId;

  return {
    editMode,
    editingCell,
    editingRowId,
    draft,
    isEditingCell,
    isEditingRow,
    getDisplayRow,
    startCellEdit,
    startRowEdit,
    setDraftValue,
    cancelEdit,
    commitCellEdit,
    commitRowEdit,
    rowOverrides,
  };
}

"use client";

import * as React from "react";

export type TableFocusCell = {
  rowIndex: number;
  colIndex: number;
};

export type UseTableKeyboardOptions = {
  enabled: boolean;
  rowCount: number;
  colCount: number;
  /** When true, Enter starts edit via callback instead of default. */
  editable?: boolean;
  onStartEdit?: (cell: TableFocusCell) => void;
  /** Skip navigation while an editor is active. */
  isEditing?: boolean;
};

export type UseTableKeyboardReturn = {
  focusedCell: TableFocusCell | null;
  setFocusedCell: React.Dispatch<React.SetStateAction<TableFocusCell | null>>;
  getCellTabIndex: (rowIndex: number, colIndex: number) => number;
  getCellProps: (
    rowIndex: number,
    colIndex: number,
  ) => {
    tabIndex: number;
    "data-focused"?: string;
    onFocus: () => void;
    onKeyDown: (event: React.KeyboardEvent) => void;
  };
};

export function useTableKeyboard({
  enabled,
  rowCount,
  colCount,
  editable = false,
  onStartEdit,
  isEditing = false,
}: UseTableKeyboardOptions): UseTableKeyboardReturn {
  const [focusedCell, setFocusedCell] = React.useState<TableFocusCell | null>(
    null,
  );

  const move = React.useCallback(
    (rowDelta: number, colDelta: number) => {
      setFocusedCell((prev) => {
        const base = prev ?? { rowIndex: 0, colIndex: 0 };
        const nextRow = Math.min(
          Math.max(base.rowIndex + rowDelta, 0),
          Math.max(rowCount - 1, 0),
        );
        const nextCol = Math.min(
          Math.max(base.colIndex + colDelta, 0),
          Math.max(colCount - 1, 0),
        );
        return { rowIndex: nextRow, colIndex: nextCol };
      });
    },
    [colCount, rowCount],
  );

  React.useEffect(() => {
    if (!enabled || !focusedCell) return;
    const selector = `[data-table-cell="${focusedCell.rowIndex}:${focusedCell.colIndex}"]`;
    const node = document.querySelector<HTMLElement>(selector);
    node?.focus({ preventScroll: false });
  }, [enabled, focusedCell]);

  const getCellTabIndex = React.useCallback(
    (rowIndex: number, colIndex: number) => {
      if (!enabled) return -1;
      if (!focusedCell) {
        return rowIndex === 0 && colIndex === 0 ? 0 : -1;
      }
      return focusedCell.rowIndex === rowIndex &&
        focusedCell.colIndex === colIndex
        ? 0
        : -1;
    },
    [enabled, focusedCell],
  );

  const onKeyDownFor = React.useCallback(
    (rowIndex: number, colIndex: number) =>
      (event: React.KeyboardEvent) => {
        if (!enabled || isEditing) return;

        switch (event.key) {
          case "ArrowUp":
            event.preventDefault();
            move(-1, 0);
            break;
          case "ArrowDown":
            event.preventDefault();
            move(1, 0);
            break;
          case "ArrowLeft":
            event.preventDefault();
            move(0, -1);
            break;
          case "ArrowRight":
            event.preventDefault();
            move(0, 1);
            break;
          case "Home":
            event.preventDefault();
            setFocusedCell({
              rowIndex: event.ctrlKey ? 0 : rowIndex,
              colIndex: 0,
            });
            break;
          case "End":
            event.preventDefault();
            setFocusedCell({
              rowIndex: event.ctrlKey ? Math.max(rowCount - 1, 0) : rowIndex,
              colIndex: Math.max(colCount - 1, 0),
            });
            break;
          case "Enter":
            if (editable) {
              event.preventDefault();
              onStartEdit?.({ rowIndex, colIndex });
            }
            break;
          default:
            break;
        }
      },
    [colCount, editable, enabled, isEditing, move, onStartEdit, rowCount],
  );

  const getCellProps = React.useCallback(
    (rowIndex: number, colIndex: number) => {
      const isFocused =
        focusedCell?.rowIndex === rowIndex &&
        focusedCell?.colIndex === colIndex;
      return {
        tabIndex: getCellTabIndex(rowIndex, colIndex),
        ...(isFocused ? { "data-focused": "true" as const } : null),
        onFocus: () => setFocusedCell({ rowIndex, colIndex }),
        onKeyDown: onKeyDownFor(rowIndex, colIndex),
      };
    },
    [focusedCell, getCellTabIndex, onKeyDownFor],
  );

  return {
    focusedCell,
    setFocusedCell,
    getCellTabIndex,
    getCellProps,
  };
}

"use client";

import { useCallback, useState } from "react";

export type UseTableSelectionOptions = {
  /** Controlled selected row ids. When provided, the hook becomes controlled. */
  selectedIds?: string[];
  /** Default selection for uncontrolled usage. */
  defaultSelectedIds?: string[];
  /** Called whenever selection changes. */
  onSelectionChange?: (selectedIds: string[]) => void;
};

export type UseTableSelectionReturn = {
  selectedIds: string[];
  isSelected: (id: string) => boolean;
  toggle: (id: string) => void;
  selectAll: (ids: string[]) => void;
  clear: () => void;
  isAllSelected: (ids: string[]) => boolean;
  isSomeSelected: (ids: string[]) => boolean;
};

/**
 * Controllable row-selection state for DataTable.
 * Supports both controlled (`selectedIds`) and uncontrolled (`defaultSelectedIds`) modes.
 */
export function useTableSelection(
  options: UseTableSelectionOptions = {},
): UseTableSelectionReturn {
  const {
    selectedIds: controlledSelectedIds,
    defaultSelectedIds = [],
    onSelectionChange,
  } = options;

  const [uncontrolledSelectedIds, setUncontrolledSelectedIds] =
    useState<string[]>(defaultSelectedIds);

  const isControlled = controlledSelectedIds !== undefined;
  const selectedIds = isControlled
    ? controlledSelectedIds
    : uncontrolledSelectedIds;

  const setSelectedIds = useCallback(
    (next: string[] | ((prev: string[]) => string[])) => {
      const resolved =
        typeof next === "function" ? next(selectedIds) : next;
      if (!isControlled) {
        setUncontrolledSelectedIds(resolved);
      }
      onSelectionChange?.(resolved);
    },
    [isControlled, onSelectionChange, selectedIds],
  );

  const isSelected = useCallback(
    (id: string) => selectedIds.includes(id),
    [selectedIds],
  );

  const toggle = useCallback(
    (id: string) => {
      setSelectedIds((prev) =>
        prev.includes(id) ? prev.filter((item) => item !== id) : [...prev, id],
      );
    },
    [setSelectedIds],
  );

  const selectAll = useCallback(
    (ids: string[]) => {
      setSelectedIds(ids);
    },
    [setSelectedIds],
  );

  const clear = useCallback(() => {
    setSelectedIds([]);
  }, [setSelectedIds]);

  const isAllSelected = useCallback(
    (ids: string[]) =>
      ids.length > 0 && ids.every((id) => selectedIds.includes(id)),
    [selectedIds],
  );

  const isSomeSelected = useCallback(
    (ids: string[]) =>
      ids.some((id) => selectedIds.includes(id)) && !isAllSelected(ids),
    [isAllSelected, selectedIds],
  );

  return {
    selectedIds,
    isSelected,
    toggle,
    selectAll,
    clear,
    isAllSelected,
    isSomeSelected,
  };
}

"use client";

import * as React from "react";
import { useVirtualizer } from "@tanstack/react-virtual";

import type { DataTableDensity } from "./types";

export const VIRTUAL_ROW_HEIGHT: Record<DataTableDensity, number> = {
  compact: 36,
  comfortable: 48,
  spacious: 56,
};

export type UseTableVirtualizationOptions = {
  enabled: boolean;
  count: number;
  scrollElement: HTMLElement | null;
  density: DataTableDensity;
  estimateSize?: number;
  overscan?: number;
};

export function useTableVirtualization({
  enabled,
  count,
  scrollElement,
  density,
  estimateSize,
  overscan = 8,
}: UseTableVirtualizationOptions) {
  const rowHeight = estimateSize ?? VIRTUAL_ROW_HEIGHT[density];

  const virtualizer = useVirtualizer({
    count: enabled ? count : 0,
    getScrollElement: () => scrollElement,
    estimateSize: () => rowHeight,
    overscan,
    enabled,
  });

  const virtualRows = enabled ? virtualizer.getVirtualItems() : [];
  const totalSize = enabled ? virtualizer.getTotalSize() : 0;
  const paddingTop =
    virtualRows.length > 0 ? (virtualRows[0]?.start ?? 0) : 0;
  const paddingBottom =
    virtualRows.length > 0
      ? totalSize - (virtualRows[virtualRows.length - 1]?.end ?? 0)
      : 0;

  return {
    enabled,
    virtualizer,
    virtualRows,
    totalSize,
    paddingTop,
    paddingBottom,
    rowHeight,
  };
}
